import React, { useState, useEffect } from 'react';
import { Menu, User, X } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

const Header: React.FC = () => {
  const [scrolled, setScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 20);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  return (
    <>
      <motion.header
        className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
          scrolled 
            ? 'bg-white/80 backdrop-blur-md border-b border-gray-100 py-4 shadow-sm' 
            : 'bg-transparent py-6'
        }`}
        initial={{ y: -100 }}
        animate={{ y: 0 }}
        transition={{ duration: 0.6, ease: [0.16, 1, 0.3, 1] }}
      >
        <div className="max-w-7xl mx-auto px-6 flex justify-between items-center">
          {/* Logo */}
          <div className="flex items-center gap-2 cursor-pointer group">
            <div className="w-8 h-8 bg-luxury-900 rounded-lg flex items-center justify-center text-white font-bold text-lg group-hover:scale-105 transition-transform duration-300">
              V
            </div>
            <span className="text-xl font-bold tracking-tight text-luxury-900">
              VANTAGE
            </span>
          </div>

          {/* Desktop Nav */}
          <nav className="hidden md:flex items-center gap-8">
            {['Funcionalidades', 'Método', 'Depoimentos', 'Preços'].map((item) => (
              <a
                key={item}
                href="#"
                className="text-sm font-medium text-gray-500 hover:text-luxury-900 transition-colors duration-200"
              >
                {item}
              </a>
            ))}
          </nav>

          {/* Actions */}
          <div className="hidden md:flex items-center gap-4">
            <button className="text-sm font-medium text-gray-600 hover:text-luxury-900">
              Login
            </button>
            <button className="flex items-center gap-2 bg-luxury-900 text-white px-5 py-2.5 rounded-full text-sm font-medium hover:bg-black transition-all hover:shadow-lg active:scale-95">
              <User size={16} />
              <span>Começar Agora</span>
            </button>
          </div>

          {/* Mobile Toggle */}
          <button 
            className="md:hidden text-gray-600"
            onClick={() => setMobileMenuOpen(true)}
          >
            <Menu size={24} />
          </button>
        </div>
      </motion.header>

      {/* Mobile Menu Overlay */}
      <AnimatePresence>
        {mobileMenuOpen && (
          <motion.div
            initial={{ opacity: 0, x: '100%' }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: '100%' }}
            transition={{ type: 'tween', duration: 0.3 }}
            className="fixed inset-0 z-[60] bg-white md:hidden"
          >
            <div className="p-6 h-full flex flex-col">
              <div className="flex justify-between items-center mb-10">
                <span className="text-xl font-bold text-luxury-900">Menu</span>
                <button onClick={() => setMobileMenuOpen(false)}>
                  <X size={24} className="text-gray-500" />
                </button>
              </div>
              <nav className="flex flex-col gap-6 text-xl font-medium text-gray-800">
                <a href="#" onClick={() => setMobileMenuOpen(false)}>Funcionalidades</a>
                <a href="#" onClick={() => setMobileMenuOpen(false)}>Método</a>
                <a href="#" onClick={() => setMobileMenuOpen(false)}>Preços</a>
              </nav>
              <div className="mt-auto flex flex-col gap-4">
                 <button className="w-full bg-luxury-900 text-white py-4 rounded-xl font-semibold">
                  Começar Agora
                </button>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

export default Header;

