const DashboardHome: React.FC<DashboardHomeProps> = ({ tasks, leads, finance, goals }) => {
  // Calculations
  const income = finance.filter(t => t.type === 'income').reduce((acc, curr) => acc + curr.amount, 0);
  const expense = finance.filter(t => t.type === 'expense').reduce((acc, curr) => acc + curr.amount, 0);
  const balance = income - expense;

  const activeLeads = leads.filter(l => l.status !== 'Closed').length;
  const closedLeads = leads.filter(l => l.status === 'Closed').length;

  const today = new Date().toISOString().split('T')[0];
  const todaysTasks = tasks.filter(t => t.date === today && !t.completed);
  const completedTasks = tasks.filter(t => t.completed).length;
  const totalTasks = tasks.length;
  const completionRate = totalTasks > 0 ? Math.round((completedTasks / totalTasks) * 100) : 0;

  return (
    <div className="space-y-6">
      {/* Stats Row */}
