import React, { useState } from 'react';
import { Plus, MoreVertical, Phone, Building2, Trash2 } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Lead } from '../types';

interface CRMViewProps {
  leads: Lead[];
  setLeads: React.Dispatch<React.SetStateAction<Lead[]>>;
}

const CRMView: React.FC<CRMViewProps> = ({ leads, setLeads }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newLead, setNewLead] = useState<Partial<Lead>>({ status: 'New' });

  const columns: { id: Lead['status']; label: string; color: string }[] = [
    { id: 'New', label: 'Novos', color: 'bg-blue-500' },
    { id: 'Qualified', label: 'Qualificados', color: 'bg-purple-500' },
    { id: 'Negotiation', label: 'Negociação', color: 'bg-yellow-500' },
    { id: 'Closed', label: 'Fechados', color: 'bg-green-500' },
  ];

  const handleAddLead = () => {
    if (!newLead.name || !newLead.value) return;
    const lead: Lead = {
      id: Date.now().toString(),
      name: newLead.name,
      company: newLead.company || '',
      value: Number(newLead.value),
      status: 'New',
      lastContact: new Date().toLocaleDateString('pt-BR'),
      phone: newLead.phone || ''
    };
    setLeads([...leads, lead]);
    setIsModalOpen(false);
    setNewLead({ status: 'New' });
  };

  const deleteLead = (id: string) => {
    setLeads(leads.filter(l => l.id !== id));
  };

  const moveLead = (id: string, newStatus: Lead['status']) => {
    setLeads(leads.map(l => l.id === id ? { ...l, status: newStatus } : l));
  };

  return (
    <div className="h-full flex flex-col">
      <div className="flex justify-between items-center mb-8">
        <div>
          <h2 className="text-2xl font-bold text-luxury-900">Gestão de Clientes</h2>
          <p className="text-gray-500">Pipeline de Vendas</p>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-luxury-900 text-white px-4 py-2 rounded-lg flex items-center gap-2 hover:bg-black transition-colors"
        >
          <Plus size={18} /> Novo Lead
        </button>
      </div>

      <div className="flex-1 overflow-x-auto">
        <div className="flex gap-6 min-w-[1000px] h-full pb-4">
          {columns.map(col => (
            <div key={col.id} className="flex-1 flex flex-col bg-gray-50 rounded-2xl p-4 border border-gray-100">
              <div className="flex items-center gap-2 mb-4 px-2">
                <div className={`w-3 h-3 rounded-full ${col.color}`} />
                <span className="font-semibold text-gray-700">{col.label}</span>
                <span className="ml-auto text-xs text-gray-400 bg-white px-2 py-1 rounded-full border">
                  {leads.filter(l => l.status === col.id).length}
                </span>
              </div>

              <div className="flex-1 space-y-3 overflow-y-auto">
                {leads.filter(l => l.status === col.id).map(lead => (
                  <motion.div 
                    layoutId={lead.id}
                    key={lead.id}
                    className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 hover:shadow-md transition-shadow group relative"
                  >
                    <div className="flex justify-between items-start mb-2">
                      <span className="font-bold text-luxury-900">{lead.name}</span>
                      <button onClick={() => deleteLead(lead.id)} className="text-gray-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity">
                        <Trash2 size={14} />
                      </button>
                    </div>
                    <div className="flex items-center gap-1 text-xs text-gray-500 mb-3">
                      <Building2 size={12} />
                      {lead.company}
                    </div>
                    <div className="flex justify-between items-center pt-3 border-t border-gray-50">
                      <span className="font-mono font-medium text-luxury-900">
                        {lead.value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 })}
                      </span>
                      {col.id !== 'Closed' && (
                        <button 
                          onClick={() => {
                            const nextStatus = columns[columns.findIndex(c => c.id === col.id) + 1]?.id;
                            if(nextStatus) moveLead(lead.id, nextStatus);
                          }}
                          className="text-xs bg-gray-100 hover:bg-luxury-900 hover:text-white px-2 py-1 rounded text-gray-600 transition-colors"
                        >
                          Mover &rarr;
                        </button>
                      )}
                    </div>
                  </motion.div>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Add Lead Modal */}
      <AnimatePresence>
        {isModalOpen && (
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-[60] bg-black/40 backdrop-blur-sm flex items-center justify-center p-4"
          >
            <div className="bg-white rounded-2xl w-full max-w-md p-6 shadow-2xl">
              <h3 className="text-xl font-bold mb-4">Novo Cliente</h3>
              <div className="space-y-4">
                <input 
                  className="w-full p-3 bg-gray-50 rounded-lg border border-gray-200 outline-none focus:border-luxury-900 transition-colors"
                  placeholder="Nome do Cliente"
                  value={newLead.name || ''}
                  onChange={e => setNewLead({...newLead, name: e.target.value})}
                />
                <input 
                  className="w-full p-3 bg-gray-50 rounded-lg border border-gray-200 outline-none focus:border-luxury-900 transition-colors"
                  placeholder="Empresa"
                  value={newLead.company || ''}
                  onChange={e => setNewLead({...newLead, company: e.target.value})}
                />
                <div className="flex gap-4">
                   <input 
                    type="number"
                    className="w-full p-3 bg-gray-50 rounded-lg border border-gray-200 outline-none focus:border-luxury-900 transition-colors"
                    placeholder="Valor Estimado (R$)"
                    value={newLead.value || ''}
                    onChange={e => setNewLead({...newLead, value: Number(e.target.value)})}
                  />
                  <input 
                    className="w-full p-3 bg-gray-50 rounded-lg border border-gray-200 outline-none focus:border-luxury-900 transition-colors"
                    placeholder="Telefone (Opcional)"
                    value={newLead.phone || ''}
                    onChange={e => setNewLead({...newLead, phone: e.target.value})}
                  />
                </div>
              </div>
              <div className="flex justify-end gap-3 mt-6">
                <button onClick={() => setIsModalOpen(false)} className="px-4 py-2 text-gray-500 hover:text-gray-800">Cancelar</button>
                <button onClick={handleAddLead} className="px-6 py-2 bg-luxury-900 text-white rounded-lg font-medium hover:bg-black">Salvar</button>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default CRMView;

import React, { useState } from 'react';
import { Plus, Check, Clock, Calendar as CalendarIcon, Trash2 } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Task } from '../types';

interface TasksViewProps {
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
}

const TasksView: React.FC<TasksViewProps> = ({ tasks, setTasks }) => {
  const [filter, setFilter] = useState<'all' | 'today' | 'business'>('all');
  const [newTaskText, setNewTaskText] = useState('');

  const today = new Date().toISOString().split('T')[0];

  const handleAddTask = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTaskText.trim()) return;
    const newTask: Task = {
      id: Date.now().toString(),
      text: newTaskText,
      completed: false,
      date: today,
      time: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
      category: 'Business' // Default
    };
    setTasks([newTask, ...tasks]);
    setNewTaskText('');
  };

  const toggleTask = (id: string) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  };

  const deleteTask = (id: string) => {
    setTasks(tasks.filter(t => t.id !== id));
  };

  const filteredTasks = tasks.filter(t => {
    if (filter === 'today') return t.date === today;
    if (filter === 'business') return t.category === 'Business';
    return true;
  });

  return (
    <div className="max-w-4xl mx-auto">
      <div className="mb-8 text-center">
        <h2 className="text-3xl font-bold text-luxury-900 mb-2">Minha Agenda</h2>
        <p className="text-gray-500">Foco total nas prioridades.</p>
      </div>

      {/* Input Area */}
      <form onSubmit={handleAddTask} className="relative mb-10">
        <input 
          type="text" 
          value={newTaskText}
          onChange={(e) => setNewTaskText(e.target.value)}
          placeholder="O que precisa ser feito hoje?" 
          className="w-full p-5 pl-6 pr-16 bg-white rounded-2xl shadow-soft border border-gray-100 text-lg outline-none focus:ring-2 focus:ring-luxury-900/10 transition-all placeholder:text-gray-400"
        />
        <button 
          type="submit"
          className="absolute right-3 top-3 bottom-3 aspect-square bg-luxury-900 text-white rounded-xl flex items-center justify-center hover:bg-black transition-colors"
        >
          <Plus size={24} />
        </button>
      </form>

      {/* Filters */}
      <div className="flex gap-2 mb-6 overflow-x-auto pb-2">
        {['all', 'today', 'business'].map((f) => (
          <button
            key={f}
            onClick={() => setFilter(f as any)}
            className={`px-4 py-2 rounded-full text-sm font-medium transition-colors whitespace-nowrap ${
              filter === f 
                ? 'bg-luxury-900 text-white' 
                : 'bg-white text-gray-500 border border-gray-200 hover:border-gray-300'
            }`}
          >
            {f === 'all' ? 'Todas' : f === 'today' ? 'Hoje' : 'Negócios'}
          </button>
        ))}
      </div>

      {/* Task List */}
      <div className="space-y-3">
        <AnimatePresence>
          {filteredTasks.length === 0 ? (
            <div className="text-center py-10 text-gray-400">
               <p>Nenhuma tarefa encontrada.</p>
            </div>
          ) : (
            filteredTasks.map((task) => (
              <motion.div
                key={task.id}
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, height: 0 }}
                className={`group flex items-center p-4 bg-white rounded-xl border transition-all ${
                  task.completed ? 'border-transparent bg-gray-50 opacity-60' : 'border-gray-100 shadow-sm hover:shadow-md'
                }`}
              >
                <button 
                  onClick={() => toggleTask(task.id)}
                  className={`w-6 h-6 rounded-full border-2 flex items-center justify-center mr-4 transition-colors ${
                    task.completed ? 'bg-green-500 border-green-500' : 'border-gray-300 hover:border-luxury-900'
                  }`}
                >
                  {task.completed && <Check size={14} className="text-white" />}
                </button>

                <div className="flex-1">
                  <p className={`text-base font-medium transition-all ${
                    task.completed ? 'text-gray-500 line-through' : 'text-gray-800'
                  }`}>
                    {task.text}
                  </p>
                  <div className="flex items-center gap-4 mt-1 text-xs text-gray-400">
                    <span className="flex items-center gap-1">
                       <Clock size={12} /> {task.time}
                    </span>
                    <span className="flex items-center gap-1">
                       <CalendarIcon size={12} /> {new Date(task.date).toLocaleDateString('pt-BR')}
                    </span>
                    <span className="text-luxury-900 font-medium bg-gray-100 px-2 rounded">
                      {task.category}
                    </span>
                  </div>
                </div>

                <button 
                  onClick={() => deleteTask(task.id)}
                  className="opacity-0 group-hover:opacity-100 p-2 text-gray-400 hover:text-red-500 transition-all"
                >
                  <Trash2 size={18} />
                </button>
              </motion.div>
            ))
          )}
        </AnimatePresence>
      </div>
    </div>
  );
};

export default TasksView;

import React, { useState } from 'react';
import { DollarSign, ArrowUpRight, ArrowDownRight, Plus, Wallet } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Transaction } from '../types';

interface FinanceViewProps {
  transactions: Transaction[];
  setTransactions: React.Dispatch<React.SetStateAction<Transaction[]>>;
}

const FinanceView: React.FC<FinanceViewProps> = ({ transactions, setTransactions }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newTrans, setNewTrans] = useState<Partial<Transaction>>({ type: 'income' });

  const income = transactions.filter(t => t.type === 'income').reduce((acc, c) => acc + c.amount, 0);
  const expense = transactions.filter(t => t.type === 'expense').reduce((acc, c) => acc + c.amount, 0);
  const balance = income - expense;

  const handleAddTransaction = () => {
    if (!newTrans.description || !newTrans.amount) return;
    const transaction: Transaction = {
      id: Date.now().toString(),
      description: newTrans.description,
      amount: Number(newTrans.amount),
      type: newTrans.type || 'income',
      date: new Date().toLocaleDateString('pt-BR'),
      category: 'Geral'
    };
    setTransactions([transaction, ...transactions]);
    setIsModalOpen(false);
    setNewTrans({ type: 'income' });
  };

  return (
    <div className="space-y-8">
      {/* Header Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-luxury-900 text-white p-6 rounded-2xl shadow-xl">
          <div className="flex justify-between items-start mb-4">
             <div className="p-2 bg-white/10 rounded-lg"><Wallet size={24} /></div>
             <span className="text-xs font-medium bg-white/20 px-2 py-1 rounded">Total</span>
          </div>
          <p className="text-sm text-gray-300">Saldo Disponível</p>
          <h3 className="text-3xl font-bold mt-1">R$ {balance.toLocaleString('pt-BR')}</h3>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm">
          <div className="flex items-center gap-3 mb-2">
            <div className="p-1.5 bg-green-100 text-green-600 rounded-lg"><ArrowUpRight size={18} /></div>
            <span className="text-sm font-semibold text-gray-600">Entradas</span>
          </div>
          <h3 className="text-2xl font-bold text-gray-800">R$ {income.toLocaleString('pt-BR')}</h3>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm">
          <div className="flex items-center gap-3 mb-2">
            <div className="p-1.5 bg-red-100 text-red-600 rounded-lg"><ArrowDownRight size={18} /></div>
            <span className="text-sm font-semibold text-gray-600">Saídas</span>
          </div>
          <h3 className="text-2xl font-bold text-gray-800">R$ {expense.toLocaleString('pt-BR')}</h3>
        </div>
      </div>

      {/* Transactions */}
      <div className="bg-white rounded-2xl shadow-soft border border-gray-100 overflow-hidden">
        <div className="p-6 border-b border-gray-100 flex justify-between items-center">
          <h3 className="font-bold text-luxury-900">Extrato Recente</h3>
          <button 
            onClick={() => setIsModalOpen(true)}
            className="flex items-center gap-2 text-sm font-semibold text-luxury-900 bg-luxury-50 px-3 py-1.5 rounded-lg hover:bg-luxury-100 transition-colors"
          >
            <Plus size={16} /> Nova Transação
          </button>
        </div>

        <div className="divide-y divide-gray-100">
          {transactions.length === 0 ? (
            <div className="p-8 text-center text-gray-400">Nenhuma transação registrada.</div>
          ) : (
            transactions.map((t) => (
              <div key={t.id} className="p-4 flex items-center justify-between hover:bg-gray-50 transition-colors">
                <div className="flex items-center gap-4">
                  <div className={`p-2 rounded-full ${t.type === 'income' ? 'bg-green-50 text-green-600' : 'bg-red-50 text-red-600'}`}>
                    <DollarSign size={18} />
                  </div>
                  <div>
                    <p className="font-medium text-gray-900">{t.description}</p>
                    <p className="text-xs text-gray-400">{t.date} • {t.category}</p>
                  </div>
                </div>
                <span className={`font-bold ${t.type === 'income' ? 'text-green-600' : 'text-red-600'}`}>
                  {t.type === 'income' ? '+' : '-'} R$ {t.amount.toLocaleString('pt-BR')}
                </span>
              </div>
            ))
          )}
        </div>
      </div>

       {/* Add Transaction Modal */}
       <AnimatePresence>
        {isModalOpen && (
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-[60] bg-black/40 backdrop-blur-sm flex items-center justify-center p-4"
          >
            <div className="bg-white rounded-2xl w-full max-w-sm p-6 shadow-2xl">
              <h3 className="text-xl font-bold mb-4">Nova Movimentação</h3>
              <div className="space-y-4">
                <div className="flex gap-2 p-1 bg-gray-100 rounded-lg">
                  {['income', 'expense'].map((type) => (
                    <button
                      key={type}
                      onClick={() => setNewTrans({...newTrans, type: type as any})}
                      className={`flex-1 py-2 rounded-md text-sm font-medium transition-all ${
                        newTrans.type === type ? 'bg-white shadow-sm text-luxury-900' : 'text-gray-500 hover:text-gray-700'
                      }`}
                    >
                      {type === 'income' ? 'Entrada' : 'Saída'}
                    </button>
                  ))}
                </div>
                <input 
                  className="w-full p-3 bg-gray-50 rounded-lg border border-gray-200 outline-none focus:border-luxury-900"
                  placeholder="Descrição (ex: Projeto X)"
                  value={newTrans.description || ''}
                  onChange={e => setNewTrans({...newTrans, description: e.target.value})}
                />
                <input 
                  type="number"
                  className="w-full p-3 bg-gray-50 rounded-lg border border-gray-200 outline-none focus:border-luxury-900"
                  placeholder="Valor (R$)"
                  value={newTrans.amount || ''}
                  onChange={e => setNewTrans({...newTrans, amount: Number(e.target.value)})}
                />
              </div>
              <div className="flex justify-end gap-3 mt-6">
                <button onClick={() => setIsModalOpen(false)} className="px-4 py-2 text-gray-500">Cancelar</button>
                <button onClick={handleAddTransaction} className="px-6 py-2 bg-luxury-900 text-white rounded-lg font-medium hover:bg-black">Confirmar</button>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default FinanceView;

import React, { useState } from 'react';
