          <Search size={16} className="text-gray-400" />
          <input 
            type="text" 
            placeholder="Buscar..." 
            className="bg-transparent border-none outline-none text-sm ml-2 w-full text-gray-700 placeholder-gray-400"
          />
        </div>

        {/* Mobile Search Icon */}
        <button className="md:hidden p-2 text-gray-500 hover:text-luxury-900">
           <Search size={20} />
        </button>

        {/* Notifications */}
        <button className="relative p-2 text-gray-500 hover:text-luxury-900 transition-colors">
          <Bell size={20} />
          <span className="absolute top-1.5 right-1.5 w-2 h-2 bg-red-500 rounded-full border border-white"></span>
        </button>
