export default Header;

import React, { useState } from 'react';
import { Plus, Building2, Trash2 } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Lead } from '../types';

interface CRMViewProps {
  leads: Lead[];
  setLeads: React.Dispatch<React.SetStateAction<Lead[]>>;
}

const CRMView: React.FC<CRMViewProps> = ({ leads, setLeads }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newLead, setNewLead] = useState<Partial<Lead>>({ status: 'New' });

  const columns: { id: Lead['status']; label: string; color: string }[] = [
    { id: 'New', label: 'Novos', color: 'bg-blue-500' },
    { id: 'Qualified', label: 'Qualificados', color: 'bg-purple-500' },
    { id: 'Negotiation', label: 'Negociação', color: 'bg-yellow-500' },
    { id: 'Closed', label: 'Fechados', color: 'bg-green-500' },
  ];

  const handleAddLead = () => {
    if (!newLead.name || !newLead.value) return;
    const lead: Lead = {
      id: Date.now().toString(),
      name: newLead.name,
      company: newLead.company || '',
      value: Number(newLead.value),
      status: 'New',
      lastContact: new Date().toLocaleDateString('pt-BR'),
      phone: newLead.phone || ''
    };
    setLeads([...leads, lead]);
    setIsModalOpen(false);
    setNewLead({ status: 'New' });
  };

  const deleteLead = (id: string) => {
    setLeads(leads.filter(l => l.id !== id));
  };

  const moveLead = (id: string, newStatus: Lead['status']) => {
    setLeads(leads.map(l => l.id === id ? { ...l, status: newStatus } : l));
  };

  return (
    <div className="h-full flex flex-col">
      <div className="flex flex-col md:flex-row md:justify-between md:items-center mb-6 gap-4">
        <div>
          <h2 className="text-xl md:text-2xl font-bold text-luxury-900">Gestão de Clientes</h2>
          <p className="text-sm text-gray-500">Pipeline de Vendas</p>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-luxury-900 text-white px-4 py-3 rounded-xl flex items-center justify-center gap-2 hover:bg-black transition-colors w-full md:w-auto shadow-lg shadow-luxury-900/20"
        >
          <Plus size={18} /> Novo Lead
        </button>
      </div>

      <div className="flex-1 -mx-4 px-4 md:mx-0 md:px-0 overflow-x-auto snap-x snap-mandatory">
        <div className="flex gap-4 md:gap-6 min-w-[320px] md:min-w-full h-full pb-4">
          {columns.map(col => (
            <div key={col.id} className="min-w-[85vw] md:min-w-[300px] flex-1 flex flex-col bg-gray-50 rounded-2xl p-4 border border-gray-100 snap-center">
              <div className="flex items-center gap-2 mb-4 px-2">
                <div className={`w-3 h-3 rounded-full ${col.color}`} />
                <span className="font-semibold text-gray-700">{col.label}</span>
                <span className="ml-auto text-xs text-gray-400 bg-white px-2 py-1 rounded-full border">
                  {leads.filter(l => l.status === col.id).length}
                </span>
              </div>

              <div className="flex-1 space-y-3 overflow-y-auto max-h-[60vh] md:max-h-full scrollbar-thin">
                {leads.filter(l => l.status === col.id).map(lead => (
                  <motion.div 
                    layoutId={lead.id}
                    key={lead.id}
                    className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 active:scale-95 transition-transform group relative"
                  >
                    <div className="flex justify-between items-start mb-2">
                      <span className="font-bold text-luxury-900 text-sm md:text-base">{lead.name}</span>
                      <button onClick={() => deleteLead(lead.id)} className="text-gray-300 hover:text-red-500 md:opacity-0 group-hover:opacity-100 transition-opacity p-1">
                        <Trash2 size={14} />
                      </button>
                    </div>
                    <div className="flex items-center gap-1 text-xs text-gray-500 mb-3">
                      <Building2 size={12} />
                      {lead.company}
                    </div>
                    <div className="flex justify-between items-center pt-3 border-t border-gray-50">
                      <span className="font-mono font-medium text-luxury-900 text-sm">
                        {lead.value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 })}
                      </span>
                      {col.id !== 'Closed' && (
                        <button 
                          onClick={() => {
                            const nextStatus = columns[columns.findIndex(c => c.id === col.id) + 1]?.id;
                            if(nextStatus) moveLead(lead.id, nextStatus);
                          }}
                          className="text-xs bg-gray-100 hover:bg-luxury-900 hover:text-white px-3 py-1.5 rounded-lg text-gray-600 transition-colors font-medium"
                        >
                          Mover &rarr;
                        </button>
                      )}
                    </div>
                  </motion.div>
                ))}
                {leads.filter(l => l.status === col.id).length === 0 && (
                   <div className="text-center py-10 text-gray-300 text-sm border-2 border-dashed border-gray-200 rounded-xl">
                     Vazio
                   </div>
                )}
              </div>
            </div>
          ))}
          {/* Spacer for mobile scroll */}
          <div className="w-1 md:hidden flex-shrink-0" /> 
        </div>
      </div>

      {/* Add Lead Modal */}
      <AnimatePresence>
        {isModalOpen && (
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-[60] bg-black/40 backdrop-blur-sm flex items-center justify-center p-4"
          >
            <motion.div 
              initial={{ scale: 0.9, y: 20 }} animate={{ scale: 1, y: 0 }}
              className="bg-white rounded-3xl w-[95%] max-w-md p-6 shadow-2xl"
            >
              <h3 className="text-xl font-bold mb-4">Novo Cliente</h3>
              <div className="space-y-4">
                <input 
                  className="w-full p-4 bg-gray-50 rounded-xl border border-gray-200 outline-none focus:border-luxury-900 transition-colors"
                  placeholder="Nome do Cliente"
                  value={newLead.name || ''}
                  onChange={e => setNewLead({...newLead, name: e.target.value})}
                />
                <input 
                  className="w-full p-4 bg-gray-50 rounded-xl border border-gray-200 outline-none focus:border-luxury-900 transition-colors"
                  placeholder="Empresa"
                  value={newLead.company || ''}
                  onChange={e => setNewLead({...newLead, company: e.target.value})}
                />
                <div className="flex gap-4">
                   <input 
                    type="number"
                    className="w-full p-4 bg-gray-50 rounded-xl border border-gray-200 outline-none focus:border-luxury-900 transition-colors"
                    placeholder="Valor (R$)"
                    value={newLead.value || ''}
                    onChange={e => setNewLead({...newLead, value: Number(e.target.value)})}
                  />
                </div>
                <input 
                    className="w-full p-4 bg-gray-50 rounded-xl border border-gray-200 outline-none focus:border-luxury-900 transition-colors"
                    placeholder="Telefone (Opcional)"
                    value={newLead.phone || ''}
                    onChange={e => setNewLead({...newLead, phone: e.target.value})}
                  />
              </div>
              <div className="flex justify-end gap-3 mt-6">
                <button onClick={() => setIsModalOpen(false)} className="px-4 py-3 text-gray-500 hover:text-gray-800 font-medium">Cancelar</button>
                <button onClick={handleAddLead} className="px-8 py-3 bg-luxury-900 text-white rounded-xl font-bold hover:bg-black shadow-lg shadow-luxury-900/20">Salvar</button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default CRMView;

import React, { useState } from 'react';
import { DollarSign, ArrowUpRight, ArrowDownRight, Plus, Wallet } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Transaction } from '../types';

interface FinanceViewProps {
  transactions: Transaction[];
  setTransactions: React.Dispatch<React.SetStateAction<Transaction[]>>;
}

const FinanceView: React.FC<FinanceViewProps> = ({ transactions, setTransactions }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newTrans, setNewTrans] = useState<Partial<Transaction>>({ type: 'income' });

  const income = transactions.filter(t => t.type === 'income').reduce((acc, c) => acc + c.amount, 0);
  const expense = transactions.filter(t => t.type === 'expense').reduce((acc, c) => acc + c.amount, 0);
  const balance = income - expense;

  const handleAddTransaction = () => {
    if (!newTrans.description || !newTrans.amount) return;
    const transaction: Transaction = {
      id: Date.now().toString(),
      description: newTrans.description,
      amount: Number(newTrans.amount),
      type: newTrans.type || 'income',
      date: new Date().toLocaleDateString('pt-BR'),
      category: 'Geral'
    };
    setTransactions([transaction, ...transactions]);
    setIsModalOpen(false);
    setNewTrans({ type: 'income' });
  };

  return (
    <div className="space-y-8">
      {/* Header Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 md:gap-6">
        <div className="bg-luxury-900 text-white p-6 rounded-2xl shadow-xl">
          <div className="flex justify-between items-start mb-4">
             <div className="p-2 bg-white/10 rounded-lg"><Wallet size={24} /></div>
             <span className="text-xs font-medium bg-white/20 px-2 py-1 rounded">Total</span>
          </div>
          <p className="text-sm text-gray-300">Saldo Disponível</p>
          <h3 className="text-3xl font-bold mt-1">R$ {balance.toLocaleString('pt-BR')}</h3>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm">
          <div className="flex items-center gap-3 mb-2">
            <div className="p-1.5 bg-green-100 text-green-600 rounded-lg"><ArrowUpRight size={18} /></div>
            <span className="text-sm font-semibold text-gray-600">Entradas</span>
          </div>
          <h3 className="text-2xl font-bold text-gray-800">R$ {income.toLocaleString('pt-BR')}</h3>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm">
          <div className="flex items-center gap-3 mb-2">
            <div className="p-1.5 bg-red-100 text-red-600 rounded-lg"><ArrowDownRight size={18} /></div>
            <span className="text-sm font-semibold text-gray-600">Saídas</span>
          </div>
          <h3 className="text-2xl font-bold text-gray-800">R$ {expense.toLocaleString('pt-BR')}</h3>
        </div>
      </div>

      {/* Transactions */}
      <div className="bg-white rounded-2xl shadow-soft border border-gray-100 overflow-hidden">
        <div className="p-6 border-b border-gray-100 flex justify-between items-center">
          <h3 className="font-bold text-luxury-900 text-lg">Extrato</h3>
          <button 
            onClick={() => setIsModalOpen(true)}
            className="flex items-center gap-2 text-sm font-semibold text-luxury-900 bg-luxury-50 px-3 py-2 rounded-xl hover:bg-luxury-100 transition-colors"
          >
            <Plus size={16} /> <span className="hidden md:inline">Nova Transação</span> <span className="md:hidden">Add</span>
          </button>
        </div>

        <div className="divide-y divide-gray-100">
          {transactions.length === 0 ? (
            <div className="p-8 text-center text-gray-400">Nenhuma transação registrada.</div>
          ) : (
            transactions.map((t) => (
              <div key={t.id} className="p-4 flex items-center justify-between hover:bg-gray-50 transition-colors">
                <div className="flex items-center gap-4">
                  <div className={`p-2 rounded-full flex-shrink-0 ${t.type === 'income' ? 'bg-green-50 text-green-600' : 'bg-red-50 text-red-600'}`}>
                    <DollarSign size={18} />
                  </div>
                  <div className="min-w-0">
                    <p className="font-medium text-gray-900 truncate">{t.description}</p>
                    <p className="text-xs text-gray-400">{t.date} • {t.category}</p>
                  </div>
                </div>
                <span className={`font-bold ml-2 whitespace-nowrap ${t.type === 'income' ? 'text-green-600' : 'text-red-600'}`}>
                  {t.type === 'income' ? '+' : '-'} R$ {t.amount.toLocaleString('pt-BR')}
                </span>
              </div>
            ))
          )}
        </div>
      </div>

       {/* Add Transaction Modal */}
       <AnimatePresence>
        {isModalOpen && (
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-[60] bg-black/40 backdrop-blur-sm flex items-center justify-center p-4"
          >
            <motion.div 
              initial={{ scale: 0.95 }} animate={{ scale: 1 }}
              className="bg-white rounded-3xl w-[95%] max-w-sm p-6 shadow-2xl"
            >
              <h3 className="text-xl font-bold mb-6">Nova Movimentação</h3>
              <div className="space-y-4">
                <div className="flex gap-2 p-1 bg-gray-100 rounded-xl">
                  {['income', 'expense'].map((type) => (
                    <button
                      key={type}
                      onClick={() => setNewTrans({...newTrans, type: type as any})}
                      className={`flex-1 py-3 rounded-lg text-sm font-bold transition-all ${
                        newTrans.type === type ? 'bg-white shadow-md text-luxury-900' : 'text-gray-500 hover:text-gray-700'
                      }`}
                    >
                      {type === 'income' ? 'Entrada' : 'Saída'}
                    </button>
                  ))}
                </div>
                <input 
                  className="w-full p-4 bg-gray-50 rounded-xl border border-gray-200 outline-none focus:border-luxury-900"
                  placeholder="Descrição (ex: Projeto X)"
                  value={newTrans.description || ''}
                  onChange={e => setNewTrans({...newTrans, description: e.target.value})}
                />
                <input 
                  type="number"
                  className="w-full p-4 bg-gray-50 rounded-xl border border-gray-200 outline-none focus:border-luxury-900"
                  placeholder="Valor (R$)"
                  value={newTrans.amount || ''}
                  onChange={e => setNewTrans({...newTrans, amount: Number(e.target.value)})}
                />
              </div>
              <div className="flex justify-end gap-3 mt-8">
                <button onClick={() => setIsModalOpen(false)} className="px-6 py-3 text-gray-500 font-medium">Cancelar</button>
                <button onClick={handleAddTransaction} className="px-8 py-3 bg-luxury-900 text-white rounded-xl font-bold hover:bg-black shadow-lg shadow-luxury-900/20">Confirmar</button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default FinanceView;

import React, { useState } from 'react';
import { Target, Plus, ChevronRight } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Goal } from '../types';

interface GoalsViewProps {
  goals: Goal[];
  setGoals: React.Dispatch<React.SetStateAction<Goal[]>>;
}

const GoalsView: React.FC<GoalsViewProps> = ({ goals, setGoals }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newGoal, setNewGoal] = useState<Partial<Goal>>({});

  const handleAddGoal = () => {
    if (!newGoal.title || !newGoal.targetValue) return;
    const goal: Goal = {
      id: Date.now().toString(),
      title: newGoal.title,
      targetValue: Number(newGoal.targetValue),
      currentValue: Number(newGoal.currentValue) || 0,
      deadline: newGoal.deadline || '2024-12-31',
      unit: newGoal.unit || 'un'
    };
    setGoals([...goals, goal]);
    setIsModalOpen(false);
    setNewGoal({});
  };

  const updateProgress = (id: string, amount: number) => {
     setGoals(goals.map(g => {
       if (g.id === id) {
         const newVal = Math.min(g.targetValue, g.currentValue + amount);
         return { ...g, currentValue: newVal };
       }
       return g;
     }));
  };

  return (
    <div className="space-y-8">
      <div className="flex flex-col md:flex-row md:justify-between md:items-end gap-4">
        <div>
           <h2 className="text-2xl md:text-3xl font-bold text-luxury-900">Metas & Objetivos</h2>
           <p className="text-gray-500 text-sm md:text-base">Visualização do seu progresso anual.</p>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-luxury-900 text-white px-5 py-3 rounded-full font-medium hover:shadow-lg hover:scale-105 transition-all flex items-center justify-center gap-2 w-full md:w-auto shadow-lg shadow-luxury-900/20"
        >
          <Plus size={18} /> Nova Meta
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {goals.map((goal) => {
          const progress = Math.min(100, Math.round((goal.currentValue / goal.targetValue) * 100));
          return (
            <motion.div 
              key={goal.id}
              initial={{ opacity: 0, scale: 0.95 }}
              animate={{ opacity: 1, scale: 1 }}
              className="bg-white p-6 rounded-2xl shadow-soft border border-gray-100 flex flex-col h-64"
            >
              <div className="flex justify-between items-start mb-4">
                <div className="p-3 bg-blue-50 text-blue-600 rounded-xl">
                  <Target size={24} />
                </div>
                <span className="text-xs font-semibold bg-gray-100 px-2 py-1 rounded text-gray-500">
                  Até {new Date(goal.deadline).toLocaleDateString('pt-BR')}
                </span>
              </div>

              <h3 className="text-xl font-bold text-gray-900 mb-1">{goal.title}</h3>
              <p className="text-sm text-gray-400 mb-6">
                {goal.currentValue} / {goal.targetValue} {goal.unit}
              </p>

              <div className="mt-auto">
                <div className="flex justify-between text-xs font-bold mb-2">
                  <span>Progresso</span>
                  <span>{progress}%</span>
                </div>
                <div className="h-3 bg-gray-100 rounded-full overflow-hidden mb-4">
                  <motion.div 
                    initial={{ width: 0 }}
                    animate={{ width: `${progress}%` }}
                    transition={{ duration: 1, ease: "easeOut" }}
                    className="h-full bg-gradient-to-r from-blue-500 to-indigo-600 rounded-full"
                  />
                </div>
                <div className="flex gap-2">
                   <button 
                     onClick={() => updateProgress(goal.id, goal.targetValue * 0.1)}
                     className="flex-1 text-xs font-semibold py-2 bg-gray-50 hover:bg-gray-100 rounded-lg transition-colors"
                   >
                     + 10%
                   </button>
                   <button 
                     onClick={() => updateProgress(goal.id, 1)} // Simplified increment
                     className="flex-1 text-xs font-semibold py-2 bg-gray-50 hover:bg-gray-100 rounded-lg transition-colors"
                   >
                     + 1 {goal.unit}
                   </button>
                </div>
              </div>
            </motion.div>
          );
        })}

        {goals.length === 0 && (
          <div 
            onClick={() => setIsModalOpen(true)}
            className="border-2 border-dashed border-gray-200 rounded-2xl flex flex-col items-center justify-center p-6 text-gray-400 hover:border-luxury-900 hover:text-luxury-900 cursor-pointer transition-all h-64 active:scale-95"
          >
            <Plus size={48} className="mb-2 opacity-20" />
            <span className="font-medium">Criar primeira meta</span>
          </div>
        )}
      </div>

       {/* Add Goal Modal */}
       <AnimatePresence>
        {isModalOpen && (
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-[60] bg-black/40 backdrop-blur-sm flex items-center justify-center p-4"
          >
            <motion.div 
              initial={{ scale: 0.9 }} animate={{ scale: 1 }}
              className="bg-white rounded-3xl w-[95%] max-w-sm p-6 shadow-2xl"
            >
              <h3 className="text-xl font-bold mb-6">Definir Meta</h3>
              <div className="space-y-4">
                <input 
                  className="w-full p-4 bg-gray-50 rounded-xl border border-gray-200 outline-none focus:border-luxury-900"
                  placeholder="Título (ex: Faturar 100k)"
                  value={newGoal.title || ''}
                  onChange={e => setNewGoal({...newGoal, title: e.target.value})}
                />
                <div className="flex gap-4">
                  <input 
                    type="number"
                    className="w-full p-4 bg-gray-50 rounded-xl border border-gray-200 outline-none focus:border-luxury-900"
                    placeholder="Alvo (Valor)"
                    value={newGoal.targetValue || ''}
                    onChange={e => setNewGoal({...newGoal, targetValue: Number(e.target.value)})}
                  />
                  <input 
                    className="w-24 p-4 bg-gray-50 rounded-xl border border-gray-200 outline-none focus:border-luxury-900"
                    placeholder="Un."
                    value={newGoal.unit || ''}
                    onChange={e => setNewGoal({...newGoal, unit: e.target.value})}
                  />
                </div>
                 <input 
                    type="date"
                    className="w-full p-4 bg-gray-50 rounded-xl border border-gray-200 outline-none focus:border-luxury-900"
                    value={newGoal.deadline || ''}
                    onChange={e => setNewGoal({...newGoal, deadline: e.target.value})}
                  />
              </div>
              <div className="flex justify-end gap-3 mt-8">
                <button onClick={() => setIsModalOpen(false)} className="px-6 py-3 text-gray-500 font-medium">Cancelar</button>
                <button onClick={handleAddGoal} className="px-8 py-3 bg-luxury-900 text-white rounded-xl font-bold hover:bg-black shadow-lg shadow-luxury-900/20">Criar</button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default GoalsView;

