import React, { useState } from 'react';
import { Plus, Check, Clock, Calendar as CalendarIcon, Trash2, Briefcase, Dumbbell, Bell } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Task } from '../types';

interface TasksViewProps {
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
}

const TasksView: React.FC<TasksViewProps> = ({ tasks, setTasks }) => {
  const [filter, setFilter] = useState<'all' | 'today' | 'pending'>('all');
  const [newTaskText, setNewTaskText] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<Task['category']>('Trabalho');

  const today = new Date().toISOString().split('T')[0];

  const handleAddTask = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTaskText.trim()) return;
    const newTask: Task = {
      id: Date.now().toString(),
      text: newTaskText,
      completed: false,
      date: today,
      time: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
      category: selectedCategory
    };
    setTasks([newTask, ...tasks]);
    setNewTaskText('');
  };

  const toggleTask = (id: string) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  };

  const deleteTask = (id: string) => {
    setTasks(tasks.filter(t => t.id !== id));
  };

  const filteredTasks = tasks.filter(t => {
    if (filter === 'today') return t.date === today;
    if (filter === 'pending') return !t.completed;
    return true;
  });

  const getCategoryIcon = (cat: Task['category']) => {
    switch (cat) {
      case 'Academia': return <Dumbbell size={14} />;
      case 'Trabalho': return <Briefcase size={14} />;
      case 'Lembrete': return <Bell size={14} />;
    }
  };

  const getCategoryColor = (cat: Task['category']) => {
    switch (cat) {
      case 'Academia': return 'bg-orange-100 text-orange-700';
      case 'Trabalho': return 'bg-blue-100 text-blue-700';
      case 'Lembrete': return 'bg-purple-100 text-purple-700';
    }
  };

  return (
    <div className="max-w-4xl mx-auto">
      <div className="mb-8 text-center md:text-left">
        <h2 className="text-3xl font-bold text-luxury-900 mb-1">Rotina Diária</h2>
        <p className="text-gray-500">Organize trabalho, treinos e lembretes.</p>
      </div>

      {/* Input Area */}
      <form onSubmit={handleAddTask} className="relative mb-8 bg-white p-4 rounded-2xl shadow-soft border border-gray-100">
        <div className="flex flex-col gap-4">
          <input 
            type="text" 
            value={newTaskText}
            onChange={(e) => setNewTaskText(e.target.value)}
            placeholder="Nova tarefa..." 
            className="w-full text-lg outline-none placeholder:text-gray-400 text-gray-800"
          />
          <div className="flex justify-between items-center">
            <div className="flex gap-2">
              {(['Trabalho', 'Academia', 'Lembrete'] as Task['category'][]).map(cat => (
                <button
                  key={cat}
                  type="button"
                  onClick={() => setSelectedCategory(cat)}
                  className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${
                    selectedCategory === cat 
                      ? 'bg-luxury-900 text-white shadow-md' 
                      : 'bg-gray-100 text-gray-500 hover:bg-gray-200'
                  }`}
                >
                  {cat === 'Academia' && <Dumbbell size={12} />}
                  {cat === 'Trabalho' && <Briefcase size={12} />}
                  {cat === 'Lembrete' && <Bell size={12} />}
                  {cat}
                </button>
              ))}
            </div>
            <button 
              type="submit"
              className="w-10 h-10 bg-luxury-900 text-white rounded-xl flex items-center justify-center hover:bg-black transition-colors shadow-lg shadow-luxury-900/20"
            >
              <Plus size={20} />
            </button>
          </div>
        </div>
      </form>

      {/* Filters */}
      <div className="flex gap-2 mb-6 overflow-x-auto pb-2 no-scrollbar">
        {['all', 'today', 'pending'].map((f) => (
          <button
            key={f}
            onClick={() => setFilter(f as any)}
            className={`px-5 py-2 rounded-full text-sm font-medium transition-colors whitespace-nowrap ${
              filter === f 
                ? 'bg-white border-luxury-900 border text-luxury-900 shadow-sm' 
                : 'bg-transparent text-gray-400 hover:text-gray-600'
            }`}
          >
            {f === 'all' ? 'Tudo' : f === 'today' ? 'Hoje' : 'Pendentes'}
          </button>
        ))}
      </div>

      {/* Task List */}
      <div className="space-y-3 pb-20">
        <AnimatePresence mode="popLayout">
          {filteredTasks.length === 0 ? (
            <div className="text-center py-16 flex flex-col items-center opacity-40">
               <Check size={48} className="mb-4 text-gray-400" />
               <p className="text-gray-500">Tudo feito por hoje.</p>
            </div>
          ) : (
            filteredTasks.map((task) => (
              <motion.div
                layout
                key={task.id}
                initial={{ opacity: 0, scale: 0.95 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0, scale: 0.95 }}
                className={`group flex items-center p-4 bg-white rounded-2xl border transition-all ${
                  task.completed ? 'border-transparent bg-gray-50/50' : 'border-gray-100 shadow-sm'
                }`}
              >
                <button 
                  onClick={() => toggleTask(task.id)}
                  className={`flex-shrink-0 w-6 h-6 rounded-full border-2 flex items-center justify-center mr-4 transition-all duration-300 ${
                    task.completed ? 'bg-green-500 border-green-500 scale-110' : 'border-gray-300 hover:border-luxury-900'
                  }`}
                >
                  {task.completed && <Check size={14} className="text-white" />}
                </button>

                <div className={`flex-1 transition-opacity duration-300 ${task.completed ? 'opacity-40' : 'opacity-100'}`}>
                  <p className={`text-base font-medium ${task.completed ? 'text-gray-500 line-through' : 'text-gray-800'}`}>
                    {task.text}
                  </p>
                  <div className="flex items-center gap-3 mt-1.5">
                    <span className={`flex items-center gap-1.5 text-[10px] font-bold px-2 py-0.5 rounded-md ${getCategoryColor(task.category)}`}>
                       {getCategoryIcon(task.category)} {task.category}
                    </span>
                    <span className="flex items-center gap-1 text-xs text-gray-400">
                       <Clock size={12} /> {task.time}
                    </span>
                  </div>
                </div>

                <button 
                  onClick={() => deleteTask(task.id)}
                  className="opacity-0 group-hover:opacity-100 p-2 text-gray-300 hover:text-red-500 transition-all"
                >
                  <Trash2 size={18} />
                </button>
              </motion.div>
            ))
          )}
        </AnimatePresence>
      </div>
    </div>
  );
};

export default TasksView;

import React, { useState } from 'react';
import { Plus, Building2, Trash2, Wallet, Users } from 'lucide-react';
