import { Lead } from '../types';

interface CRMViewProps {
  leads: Lead[];
  setLeads: React.Dispatch<React.SetStateAction<Lead[]>>;
}

const CRMView: React.FC<CRMViewProps> = ({ leads, setLeads }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newLead, setNewLead] = useState<Partial<Lead>>({ status: 'Potencial' });

  // Customized columns for Client Management
  const columns: { id: Lead['status']; label: string; color: string; bg: string }[] = [
    { id: 'Potencial', label: 'Interessados', color: 'bg-blue-500', bg: 'bg-blue-50' },
    { id: 'Negociacao', label: 'Em Negociação', color: 'bg-yellow-500', bg: 'bg-yellow-50' },
    { id: 'Ativo', label: 'Ativos (Mensal)', color: 'bg-green-500', bg: 'bg-green-100' }, // Highlighted
    { id: 'Arquivado', label: 'Arquivados', color: 'bg-gray-400', bg: 'bg-gray-50' },
  ];

  // Calculate Monthly Recurring Revenue (MRR)
  const monthlyRevenue = leads
    .filter(l => l.status === 'Ativo')
    .reduce((acc, curr) => acc + curr.value, 0);

  const activeClientsCount = leads.filter(l => l.status === 'Ativo').length;

  const handleAddLead = () => {
    if (!newLead.name || !newLead.value) return;
    const lead: Lead = {
      id: Date.now().toString(),
      name: newLead.name,
      company: newLead.company || 'Pessoal',
      value: Number(newLead.value),
      status: 'Potencial',
      lastContact: new Date().toLocaleDateString('pt-BR'),
      phone: newLead.phone || ''
    };
    setLeads([...leads, lead]);
    setIsModalOpen(false);
    setNewLead({ status: 'Potencial' });
  };

  const deleteLead = (id: string) => {
    setLeads(leads.filter(l => l.id !== id));
  };

  const moveLead = (id: string, newStatus: Lead['status']) => {
    setLeads(leads.map(l => l.id === id ? { ...l, status: newStatus } : l));
  };

  return (
    <div className="h-full flex flex-col">
      {/* MRR Summary Header */}
      <div className="bg-luxury-900 text-white rounded-2xl p-6 mb-8 shadow-xl flex flex-col md:flex-row justify-between items-center gap-4">
        <div className="flex items-center gap-4">
          <div className="p-3 bg-white/10 rounded-xl">
            <Wallet size={32} className="text-green-400" />
          </div>
          <div>
            <p className="text-gray-400 text-sm font-medium">Faturamento Mensal (Recorrente)</p>
            <h2 className="text-3xl font-bold tracking-tight">R$ {monthlyRevenue.toLocaleString('pt-BR')}</h2>
          </div>
        </div>
        <div className="flex items-center gap-6">
           <div className="text-right hidden md:block">
              <p className="text-2xl font-bold">{activeClientsCount}</p>
              <p className="text-xs text-gray-400">Clientes Ativos</p>
           </div>
           <button 
            onClick={() => setIsModalOpen(true)}
            className="bg-white text-luxury-900 px-5 py-3 rounded-xl flex items-center gap-2 hover:bg-gray-100 transition-colors font-bold shadow-lg"
          >
            <Plus size={18} /> Novo Cliente
          </button>
        </div>
      </div>

      {/* Kanban Board */}
      <div className="flex-1 -mx-4 px-4 md:mx-0 md:px-0 overflow-x-auto snap-x snap-mandatory">
        <div className="flex gap-4 min-w-[320px] md:min-w-full h-full pb-4">
          {columns.map(col => (
            <div key={col.id} className={`min-w-[85vw] md:min-w-[300px] flex-1 flex flex-col rounded-3xl p-4 border snap-center ${col.id === 'Ativo' ? 'bg-green-50/50 border-green-100' : 'bg-gray-50 border-gray-100'}`}>
              <div className="flex items-center gap-2 mb-4 px-2">
                <div className={`w-3 h-3 rounded-full ${col.color}`} />
                <span className={`font-bold ${col.id === 'Ativo' ? 'text-green-800' : 'text-gray-700'}`}>{col.label}</span>
                <span className="ml-auto text-xs font-bold text-gray-500 bg-white px-2 py-1 rounded-full shadow-sm">
                  {leads.filter(l => l.status === col.id).length}
                </span>
              </div>

              <div className="flex-1 space-y-3 overflow-y-auto max-h-[60vh] md:max-h-full scrollbar-thin">
                {leads.filter(l => l.status === col.id).map(lead => (
                  <motion.div 
                    layoutId={lead.id}
                    key={lead.id}
                    className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 active:scale-95 transition-transform group relative"
                  >
                    <div className="flex justify-between items-start mb-1">
                      <span className="font-bold text-luxury-900 text-base">{lead.name}</span>
                      <button onClick={() => deleteLead(lead.id)} className="text-gray-300 hover:text-red-500 md:opacity-0 group-hover:opacity-100 transition-opacity p-1">
                        <Trash2 size={14} />
                      </button>
                    </div>
                    <div className="flex items-center gap-1 text-xs text-gray-500 mb-3">
                      <Building2 size={12} />
                      {lead.company}
                    </div>
                    <div className="flex justify-between items-center pt-3 border-t border-gray-50">
                      <div className="flex flex-col">
                        <span className="text-[10px] text-gray-400 uppercase font-bold">Mensalidade</span>
                        <span className="font-mono font-bold text-luxury-900 text-sm">
                          {lead.value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 })}
                        </span>
                      </div>

                      {/* Movement Controls */}
                      <div className="flex gap-1">
                        {col.id !== 'Ativo' && (
                          <button 
                            onClick={() => moveLead(lead.id, 'Ativo')}
                            className="text-[10px] bg-green-100 text-green-700 hover:bg-green-200 px-2 py-1.5 rounded-lg transition-colors font-bold"
