                </div>
                <input 
                    className="w-full p-4 bg-gray-50 rounded-xl border border-gray-200 outline-none focus:border-luxury-900 transition-colors"
                    placeholder="Telefone / Contato"
                    value={newLead.phone || ''}
                    onChange={e => setNewLead({...newLead, phone: e.target.value})}
                  />
              </div>
              <div className="flex justify-end gap-3 mt-6">
                <button onClick={() => setIsModalOpen(false)} className="px-4 py-3 text-gray-500 hover:text-gray-800 font-medium">Cancelar</button>
                <button onClick={handleAddLead} className="px-8 py-3 bg-luxury-900 text-white rounded-xl font-bold hover:bg-black shadow-lg shadow-luxury-900/20">Salvar Cliente</button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

