    <div className="space-y-6 pb-4">
      {/* Stats Row - Updated Layout */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 md:gap-6">
        <StatCard 
          label="Renda Mensal" 
          value={`R$ ${monthlyRecurring.toLocaleString('pt-BR')}`} 
          trend="Recorrente" 
          isPositive={true} 
          icon={DollarSign} 
        />
        <StatCard 
          label="A Fazer Hoje" 
          value={pendingTasks.length.toString()} 
          trend={`${gymTasks} Treino • ${workTasks} Trab`} 
          isPositive={true} 
          icon={Clock} 
        />
        <StatCard 
          label="Concluído Hoje" 
          value={completedToday.toString()} 
          trend="Produtividade" 
          isPositive={true} 
          icon={CheckCircle2} 
        />
        <StatCard 
          label="Metas Ativas" 
          value={goals.length.toString()} 
          trend="Objetivos" 
          isPositive={true} 
          icon={Trophy} 
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Main Content: Daily Routine */}
        <div className="lg:col-span-2 space-y-6">
          <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="bg-white rounded-3xl border border-gray-100 shadow-soft p-5 md:p-6 min-h-[400px]"
          >
            <div className="flex justify-between items-center mb-6">
