interface TasksViewProps {
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
}

const TasksView: React.FC<TasksViewProps> = ({ tasks, setTasks }) => {
  const [filter, setFilter] = useState<'all' | 'today' | 'pending'>('all');
  const [newTaskText, setNewTaskText] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<Task['category']>('Trabalho');
  const [showSuccess, setShowSuccess] = useState(false); // State for feedback animation

  // Ref to track sent notifications to prevent spamming
  const notifiedTasks = useRef(new Set<string>());

  const today = new Date().toISOString().split('T')[0];

  // --- Notification Logic ---
  useEffect(() => {
    // 1. Request Permission on mount
    if ('Notification' in window && Notification.permission === 'default') {
      Notification.requestPermission();
    }

    const checkReminders = () => {
      if (!('Notification' in window) || Notification.permission !== 'granted') return;

      const now = new Date();

      tasks.forEach(task => {
        // Skip if completed or already notified in this session
        if (task.completed || notifiedTasks.current.has(task.id)) return;

        // Parse task datetime safely
        const taskDateTime = new Date(`${task.date}T${task.time}`);

        // Calculate difference in minutes
        const diffMs = taskDateTime.getTime() - now.getTime();
        const diffMinutes = Math.floor(diffMs / 60000);

        // Trigger if exactly 60 minutes remaining (checking window 59-60 to be safe with interval)
        if (diffMinutes === 60) {
          try {
            new Notification(`Lembrete: ${task.category}`, {
              body: `Falta 1 hora para: "${task.text}"`,
              // Using a generic calendar icon or the app icon
              icon: 'https://cdn-icons-png.flaticon.com/512/3135/3135715.png',
              silent: false
            });
            // Mark as notified
            notifiedTasks.current.add(task.id);
          } catch (error) {
            console.error("Erro ao enviar notificação:", error);
          }
        }
      });
    };

    // Check immediately and then every minute
    checkReminders();
    const interval = setInterval(checkReminders, 60000);

    return () => clearInterval(interval);
  }, [tasks]);

  const handleAddTask = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTaskText.trim()) return;

    const newTask: Task = {
      id: Date.now().toString(),
      text: newTaskText,
      completed: false,
      date: today,
      time: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
      category: selectedCategory
    };

    setTasks([newTask, ...tasks]);
    setNewTaskText('');

    // Trigger Success Feedback
    setShowSuccess(true);
    setTimeout(() => setShowSuccess(false), 1500);
  };

  const toggleTask = (id: string) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  };

  const deleteTask = (id: string) => {
    setTasks(tasks.filter(t => t.id !== id));
  };

  const filteredTasks = tasks.filter(t => {
    if (filter === 'today') return t.date === today;
    if (filter === 'pending') return !t.completed;
    return true;
  });

  const getCategoryIcon = (cat: Task['category']) => {
    switch (cat) {
      case 'Academia': return <Dumbbell size={14} />;
      case 'Trabalho': return <Briefcase size={14} />;
      case 'Lembrete': return <Bell size={14} />;
    }
  };

  const getCategoryColor = (cat: Task['category']) => {
    switch (cat) {
      case 'Academia': return 'bg-orange-100 text-orange-700';
      case 'Trabalho': return 'bg-blue-100 text-blue-700';
      case 'Lembrete': return 'bg-purple-100 text-purple-700';
    }
  };

  return (
    <div className="max-w-4xl mx-auto">
      <div className="mb-8 text-center md:text-left flex justify-between items-end">
        <div>
          <h2 className="text-3xl font-bold text-luxury-900 mb-1">Rotina Diária</h2>
          <p className="text-gray-500">Organize trabalho, treinos e lembretes.</p>
        </div>

        {/* Permission Status Indicator */}
        {'Notification' in window && Notification.permission === 'granted' && (
          <div className="hidden md:flex items-center gap-1 text-xs font-medium text-green-600 bg-green-50 px-2 py-1 rounded-full">
            <Bell size={12} /> Notificações Ativas
          </div>
        )}
      </div>

      {/* Input Area */}
      <form onSubmit={handleAddTask} className="relative mb-8 bg-white p-4 rounded-2xl shadow-soft border border-gray-100">
        <div className="flex flex-col gap-4">
          <input 
            type="text" 
            value={newTaskText}
            onChange={(e) => setNewTaskText(e.target.value)}
            placeholder="Nova tarefa..." 
            className="w-full text-lg outline-none placeholder:text-gray-400 text-gray-800"
          />
          <div className="flex justify-between items-center">
            <div className="flex gap-2">
              {(['Trabalho', 'Academia', 'Lembrete'] as Task['category'][]).map(cat => (
                <button
                  key={cat}
                  type="button"
                  onClick={() => setSelectedCategory(cat)}
                  className={`px-3 py-1.5 rounded-lg text-xs font-bold transition-all flex items-center gap-2 ${
                    selectedCategory === cat 
                      ? 'bg-luxury-900 text-white shadow-md' 
                      : 'bg-gray-100 text-gray-500 hover:bg-gray-200'
                  }`}
                >
                  {cat === 'Academia' && <Dumbbell size={12} />}
                  {cat === 'Trabalho' && <Briefcase size={12} />}
                  {cat === 'Lembrete' && <Bell size={12} />}
                  {cat}
                </button>
              ))}
            </div>

            {/* Animated Submit Button */}
            <button 
              type="submit"
              disabled={showSuccess}
              className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all duration-300 shadow-lg ${
                showSuccess 
                  ? 'bg-green-500 text-white shadow-green-500/30 scale-105' 
                  : 'bg-luxury-900 text-white hover:bg-black shadow-luxury-900/20'
              }`}
            >
              <AnimatePresence mode="wait" initial={false}>
                {showSuccess ? (
                  <motion.div
                    key="check"
                    initial={{ scale: 0, rotate: -45 }}
                    animate={{ scale: 1, rotate: 0 }}
                    exit={{ scale: 0, rotate: 45 }}
                    transition={{ duration: 0.2 }}
                  >
                    <Check size={20} />
                  </motion.div>
                ) : (
                  <motion.div
                    key="plus"
                    initial={{ scale: 0, rotate: 45 }}
                    animate={{ scale: 1, rotate: 0 }}
                    exit={{ scale: 0, rotate: -45 }}
                    transition={{ duration: 0.2 }}
                  >
                    <Plus size={20} />
                  </motion.div>
                )}
              </AnimatePresence>
            </button>
          </div>
        </div>
      </form>

      {/* Filters */}
      <div className="flex gap-2 mb-6 overflow-x-auto pb-2 no-scrollbar">
        {['all', 'today', 'pending'].map((f) => (
          <button
            key={f}
            onClick={() => setFilter(f as any)}
            className={`px-5 py-2 rounded-full text-sm font-medium transition-colors whitespace-nowrap ${
              filter === f 
                ? 'bg-white border-luxury-900 border text-luxury-900 shadow-sm' 
                : 'bg-transparent text-gray-400 hover:text-gray-600'
            }`}
          >
            {f === 'all' ? 'Tudo' : f === 'today' ? 'Hoje' : 'Pendentes'}
          </button>
        ))}
      </div>

      {/* Task List */}
      <div className="space-y-3 pb-20">
        <AnimatePresence mode="popLayout">
          {filteredTasks.length === 0 ? (
            <div className="text-center py-16 flex flex-col items-center opacity-40">
               <Check size={48} className="mb-4 text-gray-400" />
               <p className="text-gray-500">Tudo feito por hoje.</p>
            </div>
          ) : (
            filteredTasks.map((task) => (
              <motion.div
                layout
                key={task.id}
                initial={{ opacity: 0, scale: 0.95 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0, scale: 0.95 }}
                className={`group flex items-center p-4 bg-white rounded-2xl border transition-all ${
                  task.completed ? 'border-transparent bg-gray-50/50' : 'border-gray-100 shadow-sm'
                }`}
              >
                <button 
                  onClick={() => toggleTask(task.id)}
                  className={`flex-shrink-0 w-6 h-6 rounded-full border-2 flex items-center justify-center mr-4 transition-all duration-300 ${
                    task.completed ? 'bg-green-500 border-green-500 scale-110' : 'border-gray-300 hover:border-luxury-900'
                  }`}
                >
                  {task.completed && <Check size={14} className="text-white" />}
                </button>

                <div className={`flex-1 transition-opacity duration-300 ${task.completed ? 'opacity-40' : 'opacity-100'}`}>
                  <p className={`text-base font-medium ${task.completed ? 'text-gray-500 line-through' : 'text-gray-800'}`}>
                    {task.text}
                  </p>
                  <div className="flex items-center gap-3 mt-1.5">
                    <span className={`flex items-center gap-1.5 text-[10px] font-bold px-2 py-0.5 rounded-md ${getCategoryColor(task.category)}`}>
                       {getCategoryIcon(task.category)} {task.category}
                    </span>
                    <span className="flex items-center gap-1 text-xs text-gray-400">
                       <Clock size={12} /> {task.time}
                    </span>
                  </div>
                </div>

                <button 
                  onClick={() => deleteTask(task.id)}
                  className="opacity-0 group-hover:opacity-100 p-2 text-gray-300 hover:text-red-500 transition-all"
                >
                  <Trash2 size={18} />
                </button>
              </motion.div>
            ))
          )}
        </AnimatePresence>
      </div>
    </div>
  );
};

export default TasksView;

import { LucideIcon } from "lucide-react";

export type ViewState = 'dashboard' | 'crm' | 'tasks' | 'goals';

export interface NavItem {
  id: ViewState;
  label: string;
  icon: LucideIcon;
}

export interface Task {
  id: string;
  text: string;
  completed: boolean;
  time: string; // HH:mm
  date: string; // YYYY-MM-DD
  category: 'Trabalho' | 'Academia' | 'Lembrete';
}

export interface Lead {
  id: string;
  name: string;
  company: string; // Pode ser usado como "Serviço Contratado"
  status: 'Potencial' | 'Negociacao' | 'Ativo' | 'Arquivado';
  value: number; // Valor da Mensalidade
  lastContact: string;
  phone?: string;
}

export interface Goal {
  id: string;
  title: string;
  targetValue: number;
  currentValue: number;
  deadline: string;
  unit: string; // e.g., 'livros', 'km', 'sessões'
}

export interface StatCardProps {
  label: string;
  value: string;
  trend?: string;
  isPositive?: boolean;
  icon: LucideIcon;
}

export interface FeatureCardProps {
  id: string;
  title: string;
  subtitle: string;
  icon: LucideIcon;
  ctaText: string;
  gradient: string;
}

export interface AppData {
  tasks: Task[];
  leads: Lead[];
  goals: Goal[];
}

import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import MobileNav from './components/MobileNav';
import Header from './components/Header';
import DashboardHome from './components/DashboardHome';
import CRMView from './components/CRMView';
import TasksView from './components/TasksView';
import GoalsView from './components/GoalsView';
import { ViewState, Task, Lead, Goal } from './types';
import { motion, AnimatePresence } from 'framer-motion';

function App() {
  const [activeView, setActiveView] = useState<ViewState>('dashboard');

  // --- State Initialization with LocalStorage ---
  const [tasks, setTasks] = useState<Task[]>(() => {
    const saved = localStorage.getItem('vantage_tasks');
    return saved ? JSON.parse(saved) : [];
  });

  const [leads, setLeads] = useState<Lead[]>(() => {
    const saved = localStorage.getItem('vantage_leads');
    return saved ? JSON.parse(saved) : [];
  });

  const [goals, setGoals] = useState<Goal[]>(() => {
    const saved = localStorage.getItem('vantage_goals');
    return saved ? JSON.parse(saved) : [];
  });

  // --- Persistence Effects ---
  useEffect(() => localStorage.setItem('vantage_tasks', JSON.stringify(tasks)), [tasks]);
  useEffect(() => localStorage.setItem('vantage_leads', JSON.stringify(leads)), [leads]);
  useEffect(() => localStorage.setItem('vantage_goals', JSON.stringify(goals)), [goals]);

  return (
    <div className="flex h-screen bg-luxury-50 font-sans selection:bg-luxury-900 selection:text-white overflow-hidden">
      <Sidebar activeView={activeView} setView={setActiveView} />

      <div className="flex-1 flex flex-col relative h-full">
        <Header title={activeView} />

        {/* Adjusted padding for mobile bottom nav + safe area. pb-28 ensures content clears the fixed nav */}
        <main className="flex-1 overflow-y-auto overflow-x-hidden p-4 md:p-8 scroll-smooth pb-28 lg:pb-8 pt-2">
          <div className="max-w-7xl mx-auto">
            <AnimatePresence mode="wait">
              <motion.div
                key={activeView}
                initial={{ opacity: 0, scale: 0.98 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0, scale: 0.98 }}
                transition={{ duration: 0.2 }}
              >
                {activeView === 'dashboard' && (
                  <DashboardHome 
                    tasks={tasks}
                    setTasks={setTasks} 
                    leads={leads} 
                    goals={goals} 
                  />
                )}
                {activeView === 'crm' && (
                  <CRMView leads={leads} setLeads={setLeads} />
                )}
                {activeView === 'tasks' && (
                  <TasksView tasks={tasks} setTasks={setTasks} />
                )}
                {activeView === 'goals' && (
                  <GoalsView goals={goals} setGoals={setGoals} />
                )}
              </motion.div>
            </AnimatePresence>
          </div>
        </main>

        <MobileNav activeView={activeView} setView={setActiveView} />
      </div>
    </div>
  );
}

export default App;

