import React, { useState } from 'react';
import { Plus, Building2, Trash2, Wallet, Users, LayoutList } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Lead } from '../types';

interface CRMViewProps {
  leads: Lead[];
  setLeads: React.Dispatch<React.SetStateAction<Lead[]>>;
}

const CRMView: React.FC<CRMViewProps> = ({ leads, setLeads }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newLead, setNewLead] = useState<Partial<Lead>>({ status: 'Potencial' });
  const [activeMobileTab, setActiveMobileTab] = useState<Lead['status']>('Ativo'); // Default view on mobile

  // Customized columns for Client Management
  const columns: { id: Lead['status']; label: string; color: string; bg: string }[] = [
    { id: 'Potencial', label: 'Interesse', color: 'bg-blue-500', bg: 'bg-blue-50' },
    { id: 'Negociacao', label: 'Negociando', color: 'bg-yellow-500', bg: 'bg-yellow-50' },
    { id: 'Ativo', label: 'Ativos', color: 'bg-green-500', bg: 'bg-green-100' },
    { id: 'Arquivado', label: 'Arquivados', color: 'bg-gray-400', bg: 'bg-gray-50' },
  ];

  // Calculate Monthly Recurring Revenue (MRR)
  const monthlyRevenue = leads
    .filter(l => l.status === 'Ativo')
    .reduce((acc, curr) => acc + curr.value, 0);

  const activeClientsCount = leads.filter(l => l.status === 'Ativo').length;

  const handleAddLead = () => {
    if (!newLead.name || !newLead.value) return;
    const lead: Lead = {
      id: Date.now().toString(),
      name: newLead.name,
      company: newLead.company || 'Pessoal',
      value: Number(newLead.value),
      status: 'Potencial',
      lastContact: new Date().toLocaleDateString('pt-BR'),
      phone: newLead.phone || ''
    };
    setLeads([...leads, lead]);
    setIsModalOpen(false);
    setNewLead({ status: 'Potencial' });
  };

  const deleteLead = (id: string) => {
    setLeads(leads.filter(l => l.id !== id));
  };

  const moveLead = (id: string, newStatus: Lead['status']) => {
    setLeads(leads.map(l => l.id === id ? { ...l, status: newStatus } : l));
  };

  return (
    <div className="h-full flex flex-col pb-safe">
      {/* Summary Header */}
      <div className="bg-luxury-900 text-white rounded-3xl p-5 mb-6 shadow-xl flex flex-col gap-4">
        <div className="flex justify-between items-start">
          <div className="flex items-center gap-3">
             <div className="p-2.5 bg-white/10 rounded-xl">
               <Wallet size={24} className="text-green-400" />
             </div>
             <div>
               <p className="text-gray-400 text-xs uppercase tracking-wide font-bold">MRR (Mensal)</p>
               <h2 className="text-2xl md:text-3xl font-bold tracking-tight">R$ {monthlyRevenue.toLocaleString('pt-BR', { minimumFractionDigits: 0 })}</h2>
             </div>
          </div>
          <div className="text-right">
              <p className="text-xl md:text-2xl font-bold">{activeClientsCount}</p>
              <p className="text-[10px] uppercase font-bold text-gray-500">Ativos</p>
           </div>
        </div>

        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-white text-luxury-900 w-full py-3 rounded-xl flex items-center justify-center gap-2 hover:bg-gray-100 transition-colors font-bold shadow-lg active:scale-95"
        >
          <Plus size={18} /> Novo Cliente
        </button>
      </div>

      {/* Mobile Tabs (Visible only on small screens) */}
      <div className="md:hidden flex gap-2 overflow-x-auto pb-4 no-scrollbar">
        {columns.map(col => (
          <button
            key={col.id}
            onClick={() => setActiveMobileTab(col.id)}
            className={`px-4 py-2 rounded-full text-xs font-bold whitespace-nowrap transition-all border ${
              activeMobileTab === col.id 
                ? 'bg-luxury-900 text-white border-luxury-900' 
                : 'bg-white text-gray-500 border-gray-200'
            }`}
          >
            {col.label} <span className="ml-1 opacity-70">({leads.filter(l => l.status === col.id).length})</span>
          </button>
        ))}
      </div>

      {/* Content Area */}
      <div className="flex-1 min-h-0">
        {/* Desktop View: Kanban (Grid) */}
        <div className="hidden md:flex gap-4 h-full pb-4 overflow-x-auto">
          {columns.map(col => (
             <Column 
               key={col.id} 
               col={col} 
               leads={leads} 
               moveLead={moveLead} 
               deleteLead={deleteLead} 
             />
          ))}
        </div>

        {/* Mobile View: Vertical List based on Tab */}
        <div className="md:hidden h-full">
           <AnimatePresence mode="wait">
             <motion.div
               key={activeMobileTab}
               initial={{ opacity: 0, y: 10 }}
               animate={{ opacity: 1, y: 0 }}
               exit={{ opacity: 0, y: -10 }}
               className="space-y-3 pb-20"
             >
               {leads.filter(l => l.status === activeMobileTab).length === 0 ? (
                 <div className="text-center py-12 text-gray-400 flex flex-col items-center">
                    <LayoutList size={32} className="mb-2 opacity-20" />
                    <p className="text-sm">Nenhum cliente nesta etapa.</p>
                 </div>
               ) : (
                 leads.filter(l => l.status === activeMobileTab).map(lead => (
                   <LeadCard 
                     key={lead.id} 
                     lead={lead} 
                     moveLead={moveLead} 
                     deleteLead={deleteLead} 
                     isMobile={true}
                   />
                 ))
               )}
             </motion.div>
           </AnimatePresence>
        </div>
      </div>

      {/* Add Lead Modal */}
      <AnimatePresence>
        {isModalOpen && (
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-[100] bg-black/40 backdrop-blur-sm flex items-center justify-center p-4"
          >
            <motion.div 
              initial={{ scale: 0.9, y: 20 }} animate={{ scale: 1, y: 0 }}
              className="bg-white rounded-3xl w-[95%] max-w-md p-6 shadow-2xl"
            >
              <h3 className="text-xl font-bold mb-4">Adicionar Lead</h3>
              <div className="space-y-4">
                <input 
                  className="w-full p-4 bg-gray-50 rounded-xl border border-gray-200 outline-none focus:border-luxury-900 transition-colors"
                  placeholder="Nome do Cliente"
                  value={newLead.name || ''}
                  onChange={e => setNewLead({...newLead, name: e.target.value})}
                />
                <input 
                  className="w-full p-4 bg-gray-50 rounded-xl border border-gray-200 outline-none focus:border-luxury-900 transition-colors"
                  placeholder="Serviço (ex: Consultoria)"
                  value={newLead.company || ''}
                  onChange={e => setNewLead({...newLead, company: e.target.value})}
                />
                <div className="relative">
                   <span className="absolute left-4 top-4 text-gray-400 text-sm font-bold">R$</span>
                   <input 
                    type="number"
                    className="w-full p-4 pl-10 bg-gray-50 rounded-xl border border-gray-200 outline-none focus:border-luxury-900 transition-colors font-mono"
                    placeholder="Valor Mensal"
                    value={newLead.value || ''}
                    onChange={e => setNewLead({...newLead, value: Number(e.target.value)})}
                  />
                </div>
              </div>
              <div className="flex justify-end gap-3 mt-6">
                <button onClick={() => setIsModalOpen(false)} className="px-4 py-3 text-gray-500 hover:text-gray-800 font-medium text-sm">Cancelar</button>
                <button onClick={handleAddLead} className="px-6 py-3 bg-luxury-900 text-white rounded-xl font-bold hover:bg-black shadow-lg shadow-luxury-900/20 text-sm">Salvar</button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

