import React, { useState } from 'react';
import { Target, Plus, Zap, Trophy, Flame } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Goal } from '../types';

interface GoalsViewProps {
  goals: Goal[];
  setGoals: React.Dispatch<React.SetStateAction<Goal[]>>;
}

const GoalsView: React.FC<GoalsViewProps> = ({ goals, setGoals }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newGoal, setNewGoal] = useState<Partial<Goal>>({});

  const handleAddGoal = () => {
    if (!newGoal.title || !newGoal.targetValue) return;
    const goal: Goal = {
      id: Date.now().toString(),
      title: newGoal.title,
      targetValue: Number(newGoal.targetValue),
      currentValue: Number(newGoal.currentValue) || 0,
      deadline: newGoal.deadline || '2024-12-31',
      unit: newGoal.unit || 'vezes'
    };
    setGoals([...goals, goal]);
    setIsModalOpen(false);
    setNewGoal({});
  };

  const updateProgress = (id: string, amount: number) => {
     setGoals(goals.map(g => {
       if (g.id === id) {
         const newVal = Math.min(g.targetValue, g.currentValue + amount);
         return { ...g, currentValue: newVal };
       }
       return g;
     }));
  };

  return (
    <div className="space-y-6 pb-20">
      <div className="flex flex-col md:flex-row md:justify-between md:items-end gap-4">
        <div>
           <h2 className="text-2xl md:text-3xl font-bold text-luxury-900">Desafios & Metas</h2>
           <p className="text-gray-500 text-sm md:text-base">O que você vai conquistar este mês?</p>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-luxury-900 text-white px-6 py-3 rounded-xl font-bold hover:shadow-lg transition-all flex items-center justify-center gap-2 w-full md:w-auto shadow-lg shadow-luxury-900/20 active:scale-95"
        >
          <Plus size={18} /> Criar Desafio
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {goals.map((goal) => {
          const progress = Math.min(100, Math.round((goal.currentValue / goal.targetValue) * 100));
          const isCompleted = progress === 100;

          return (
            <motion.div 
              key={goal.id}
              initial={{ opacity: 0, scale: 0.95 }}
              animate={{ opacity: 1, scale: 1 }}
              className={`p-6 rounded-3xl border flex flex-col relative overflow-hidden transition-all ${
                isCompleted 
                  ? 'bg-luxury-900 text-white border-luxury-900' 
                  : 'bg-white border-gray-100 shadow-soft'
              }`}
            >
              {isCompleted && (
                <div className="absolute top-0 right-0 p-4">
                  <Trophy size={24} className="text-yellow-400" />
                </div>
              )}

              <div className="flex justify-between items-start mb-4 relative z-10">
                <div className={`p-3 rounded-2xl ${isCompleted ? 'bg-white/10' : 'bg-orange-50 text-orange-600'}`}>
                  {isCompleted ? <Trophy size={20} /> : <Zap size={20} />}
                </div>
                {!isCompleted && (
                  <span className="text-[10px] font-bold bg-gray-100 px-2 py-1 rounded-full text-gray-500 uppercase">
                    Em andamento
                  </span>
                )}
              </div>

              <h3 className={`text-xl font-bold mb-1 ${isCompleted ? 'text-white' : 'text-gray-900'}`}>
                {goal.title}
              </h3>
              <p className={`text-sm mb-6 ${isCompleted ? 'text-gray-400' : 'text-gray-400'}`}>
                {goal.currentValue} de {goal.targetValue} {goal.unit}
              </p>

              <div className="mt-auto relative z-10">
                <div className="flex justify-between text-xs font-bold mb-2 opacity-80">
                  <span>Progresso</span>
                  <span>{progress}%</span>
                </div>
                <div className={`h-3 rounded-full overflow-hidden mb-5 ${isCompleted ? 'bg-white/20' : 'bg-gray-100'}`}>
                  <motion.div 
                    initial={{ width: 0 }}
                    animate={{ width: `${progress}%` }}
                    transition={{ duration: 1, ease: "easeOut" }}
                    className={`h-full rounded-full ${isCompleted ? 'bg-green-400' : 'bg-gradient-to-r from-orange-500 to-red-500'}`}
                  />
                </div>

                {!isCompleted && (
                  <div className="flex gap-2">
                     <button 
                       onClick={() => updateProgress(goal.id, 1)}
                       className="flex-1 text-sm font-bold py-3 bg-luxury-900 text-white rounded-xl hover:bg-black transition-colors active:scale-95 flex items-center justify-center gap-2"
                     >
                       <Plus size={16} /> Registrar +1
                     </button>
                  </div>
                )}

                {isCompleted && (
                   <div className="py-2 text-center text-sm font-bold text-green-400 border border-green-400/30 rounded-xl bg-green-400/10">
                     Desafio Concluído!
                   </div>
                )}
              </div>
            </motion.div>
          );
        })}

        {goals.length === 0 && (
          <div 
            onClick={() => setIsModalOpen(true)}
            className="border-2 border-dashed border-gray-200 rounded-3xl flex flex-col items-center justify-center p-8 text-gray-400 hover:border-luxury-900 hover:text-luxury-900 cursor-pointer transition-all min-h-[250px] active:scale-95"
          >
            <Flame size={48} className="mb-4 opacity-20" />
            <span className="font-bold text-lg">Criar Primeiro Desafio</span>
            <span className="text-sm opacity-60">Ex: Ler 5 Livros</span>
          </div>
        )}
      </div>

       {/* Add Goal Modal */}
       <AnimatePresence>
        {isModalOpen && (
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-[100] bg-black/40 backdrop-blur-sm flex items-center justify-center p-4"
          >
            <motion.div 
              initial={{ scale: 0.9 }} animate={{ scale: 1 }}
              className="bg-white rounded-3xl w-[95%] max-w-sm p-6 shadow-2xl"
            >
              <h3 className="text-xl font-bold mb-6">Novo Desafio</h3>
              <div className="space-y-4">
                <div>
                  <label className="text-xs font-bold text-gray-500 ml-1 mb-1 block">O que você vai fazer?</label>
                  <input 
                    className="w-full p-4 bg-gray-50 rounded-xl border border-gray-200 outline-none focus:border-luxury-900 transition-colors placeholder:font-normal font-bold text-gray-900"
                    placeholder="Ex: Correr 50km"
                    value={newGoal.title || ''}
                    onChange={e => setNewGoal({...newGoal, title: e.target.value})}
                  />
                </div>

                <div className="flex gap-4">
                  <div className="flex-1">
                    <label className="text-xs font-bold text-gray-500 ml-1 mb-1 block">Meta (Número)</label>
                    <input 
                      type="number"
                      className="w-full p-4 bg-gray-50 rounded-xl border border-gray-200 outline-none focus:border-luxury-900 transition-colors font-mono font-bold"
                      placeholder="50"
                      value={newGoal.targetValue || ''}
                      onChange={e => setNewGoal({...newGoal, targetValue: Number(e.target.value)})}
                    />
                  </div>
                  <div className="w-1/3">
                    <label className="text-xs font-bold text-gray-500 ml-1 mb-1 block">Unidade</label>
                    <input 
                      className="w-full p-4 bg-gray-50 rounded-xl border border-gray-200 outline-none focus:border-luxury-900 transition-colors text-center"
                      placeholder="km"
                      value={newGoal.unit || ''}
                      onChange={e => setNewGoal({...newGoal, unit: e.target.value})}
                    />
                  </div>
                </div>

                <div>
                   <label className="text-xs font-bold text-gray-500 ml-1 mb-1 block">Prazo Final</label>
                   <input 
                      type="date"
                      className="w-full p-4 bg-gray-50 rounded-xl border border-gray-200 outline-none focus:border-luxury-900 transition-colors"
                      value={newGoal.deadline || ''}
                      onChange={e => setNewGoal({...newGoal, deadline: e.target.value})}
                    />
                </div>
              </div>
              <div className="flex justify-end gap-3 mt-8">
                <button onClick={() => setIsModalOpen(false)} className="px-6 py-3 text-gray-500 font-medium text-sm">Cancelar</button>
                <button onClick={handleAddGoal} className="px-8 py-3 bg-luxury-900 text-white rounded-xl font-bold hover:bg-black shadow-lg shadow-luxury-900/20 text-sm">Criar Meta</button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default GoalsView;

import React from 'react';
import { motion } from 'framer-motion';
import { TrendingUp, Users, CheckCircle2, Clock, DollarSign, Dumbbell, Briefcase, Bell, Trophy, Check } from 'lucide-react';
import { Task, Lead, Goal, StatCardProps } from '../types';

interface DashboardHomeProps {
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>; // Added setter
  leads: Lead[];
  goals: Goal[];
}

const StatCard: React.FC<StatCardProps> = ({ label, value, trend, isPositive, icon: Icon }) => (
  <motion.div 
    whileHover={{ y: -2 }}
    className="bg-white p-4 md:p-5 rounded-2xl border border-gray-100 shadow-soft flex items-start justify-between min-w-[140px]"
  >
    <div>
      <p className="text-[10px] md:text-xs font-bold text-gray-400 mb-1 uppercase tracking-wider">{label}</p>
      <h3 className="text-lg md:text-2xl font-bold text-luxury-900">{value}</h3>
      {trend && (
        <div className={`flex items-center mt-2 text-[10px] font-bold ${isPositive ? 'text-green-600 bg-green-50' : 'text-gray-500 bg-gray-100'} w-fit px-2 py-1 rounded-full whitespace-nowrap`}>
          {trend}
        </div>
      )}
    </div>
    <div className={`p-2.5 md:p-3 rounded-xl ${label === 'Concluído Hoje' ? 'bg-green-50 text-green-600' : 'bg-luxury-50 text-luxury-900'}`}>
      <Icon size={16} className="md:w-[18px] md:h-[18px]" />
    </div>
  </motion.div>
);

const DashboardHome: React.FC<DashboardHomeProps> = ({ tasks, setTasks, leads, goals }) => {
  // Client Calculations
  const activeClients = leads.filter(l => l.status === 'Ativo');
  const monthlyRecurring = activeClients.reduce((acc, l) => acc + l.value, 0);

  // Task Calculations
  const today = new Date().toISOString().split('T')[0];
  const todaysTasks = tasks.filter(t => t.date === today);
  // Sort: Pending first, then Completed
  const sortedTasks = [...todaysTasks].sort((a, b) => Number(a.completed) - Number(b.completed));

  const pendingTasks = todaysTasks.filter(t => !t.completed);
  const completedToday = todaysTasks.filter(t => t.completed).length;

  const gymTasks = pendingTasks.filter(t => t.category === 'Academia').length;
  const workTasks = pendingTasks.filter(t => t.category === 'Trabalho').length;

  const toggleTask = (id: string) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  };

  const getCategoryStyles = (category: Task['category']) => {
    switch (category) {
      case 'Academia': return { bg: 'bg-orange-100', text: 'text-orange-600', icon: Dumbbell, dot: 'bg-orange-400' };
      case 'Trabalho': return { bg: 'bg-blue-100', text: 'text-blue-600', icon: Briefcase, dot: 'bg-blue-400' };
      default: return { bg: 'bg-purple-100', text: 'text-purple-600', icon: Bell, dot: 'bg-purple-400' };
    }
  };

  return (
    <div className="space-y-6 pb-4">
      {/* Stats Row - Updated Layout */}
      <div className="grid grid-cols-2 lg:grid-cols-4 gap-3 md:gap-6">
        <StatCard 
          label="Renda Mensal" 
          value={`R$ ${monthlyRecurring.toLocaleString('pt-BR', {notation: 'compact'})}`} 
          trend="Recorrente" 
          isPositive={true} 
          icon={DollarSign} 
        />
        <StatCard 
          label="A Fazer Hoje" 
          value={pendingTasks.length.toString()} 
          trend={`${gymTasks} Treino • ${workTasks} Trab`} 
          isPositive={true} 
          icon={Clock} 
        />
        <StatCard 
          label="Concluído Hoje" 
          value={completedToday.toString()} 
          trend="Produtividade" 
          isPositive={true} 
          icon={CheckCircle2} 
        />
        <StatCard 
          label="Metas Ativas" 
          value={goals.length.toString()} 
          trend="Desafios" 
          isPositive={true} 
          icon={Trophy} 
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Main Content: Daily Routine */}
        <div className="lg:col-span-2 space-y-6">
          <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            className="bg-white rounded-3xl border border-gray-100 shadow-soft p-5 md:p-6 min-h-[400px]"
          >
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-luxury-900">Sua Rotina Hoje</h3>
              <span className="text-xs font-medium text-gray-400 bg-gray-50 px-3 py-1 rounded-full">
                {new Date().toLocaleDateString('pt-BR', { weekday: 'long' })}
              </span>
            </div>

            {sortedTasks.length === 0 ? (
              <div className="flex flex-col items-center justify-center h-64 text-center text-gray-400">
                <CheckCircle2 size={48} className="mb-4 opacity-20" />
                <p>Nenhuma tarefa agendada.</p>
                <p className="text-sm">Toque em "Agenda" para adicionar.</p>
              </div>
            ) : (
              <div className="space-y-3">
                {sortedTasks.map((task) => {
                  const style = getCategoryStyles(task.category);
                  const Icon = style.icon;

                  return (
                    <motion.div 
                      layout
                      key={task.id} 
                      className={`flex items-center gap-4 p-4 rounded-2xl border transition-all duration-300 ${
                        task.completed 
                          ? 'bg-gray-50/50 border-transparent opacity-70' 
                          : 'bg-white border-gray-100 hover:border-luxury-200 shadow-sm'
                      }`}
                    >
                      {/* Interactive Checkbox */}
                      <button 
                        onClick={() => toggleTask(task.id)}
                        className={`flex-shrink-0 w-6 h-6 rounded-full border-2 flex items-center justify-center transition-all duration-200 ${
                          task.completed 
                            ? 'bg-green-500 border-green-500 scale-110' 
                            : 'border-gray-300 hover:border-luxury-900 bg-white'
                        }`}
                      >
                        {task.completed && <Check size={14} className="text-white" />}
                      </button>

                      {/* Icon Container */}
                      <div className={`hidden md:flex flex-shrink-0 w-10 h-10 rounded-full items-center justify-center ${style.bg} ${style.text}`}>
                        <Icon size={18} />
                      </div>

                      {/* Content */}
                      <div className="flex-1 min-w-0">
                        <p className={`text-sm md:text-base font-semibold truncate transition-colors ${task.completed ? 'text-gray-400 line-through' : 'text-gray-800'}`}>
                          {task.text}
                        </p>
                        <div className="flex items-center gap-2 mt-1">
                          <Clock size={12} className="text-gray-400" />
                          <span className="text-xs text-gray-500 font-medium">{task.time}</span>
                          <span className="md:hidden text-[10px] px-1.5 py-0.5 rounded bg-gray-100 text-gray-500">
                            {task.category}
                          </span>
                        </div>
                      </div>

                      {/* Decorative/Status Dot (Desktop only) */}
                      <div className={`hidden md:block w-2 h-2 rounded-full ${task.completed ? 'bg-gray-300' : style.dot}`} />
                    </motion.div>
                  );
                })}
              </div>
            )}
          </motion.div>
        </div>

        {/* Sidebar Content: Active Clients Highlight */}
        <div className="space-y-6">
          <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.1 }}
            className="bg-luxury-900 text-white rounded-3xl shadow-xl p-6 h-full relative overflow-hidden min-h-[300px]"
          >
            {/* Background decoration */}
            <div className="absolute top-0 right-0 w-32 h-32 bg-white/5 rounded-full blur-3xl -mr-10 -mt-10 pointer-events-none" />

            <div className="flex justify-between items-center mb-6 relative z-10">
              <h3 className="text-lg font-bold">Principais Clientes</h3>
              <Users size={18} className="text-gray-400" />
            </div>

            {activeClients.length === 0 ? (
              <div className="text-center text-gray-500 py-10 relative z-10">
                <p className="text-sm">Nenhum cliente ativo.</p>
                <p className="text-xs mt-1">Vá em CRM para adicionar.</p>
              </div>
            ) : (
              <div className="space-y-4 relative z-10">
                {activeClients
                  .sort((a, b) => b.value - a.value)
                  .slice(0, 4)
                  .map((lead) => (
                  <div key={lead.id} className="bg-white/10 p-4 rounded-xl border border-white/5 flex justify-between items-center">
                    <div>
                      <p className="font-semibold text-sm truncate max-w-[120px]">{lead.name}</p>
                      <p className="text-xs text-gray-400 truncate max-w-[120px]">{lead.company}</p>
                    </div>
                    <div className="text-right flex-shrink-0">
                       <span className="text-sm font-mono font-bold text-green-300">
                        R$ {lead.value.toLocaleString('pt-BR', { notation: "compact", maximumFractionDigits: 1 })}
                      </span>
                      <p className="text-[10px] text-gray-500">mensal</p>
                    </div>
                  </div>
                ))}
              </div>
            )}

            <div className="mt-8 pt-6 border-t border-white/10 relative z-10">
               <div className="flex justify-between items-end">
                 <div>
                    <div className="text-xs text-gray-400 mb-1">Previsão Anual</div>
                    <div className="text-xl font-bold text-gray-200">
