const Column = ({ col, leads, moveLead, deleteLead }: any) => (
  <div className={`min-w-[300px] flex-1 flex flex-col rounded-3xl p-4 border ${col.id === 'Ativo' ? 'bg-green-50/50 border-green-100' : 'bg-gray-50 border-gray-100'}`}>
