const LeadCard = ({ lead, moveLead, deleteLead, isMobile }: any) => (
  <motion.div 
    layoutId={lead.id}
    className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 active:scale-98 transition-transform group relative"
  >
    <div className="flex justify-between items-start mb-1">
      <span className="font-bold text-luxury-900 text-base">{lead.name}</span>
      <button onClick={() => deleteLead(lead.id)} className="text-gray-300 hover:text-red-500 p-1">
