           >
             Fechar
           </button>
         )}
         {lead.status === 'Ativo' && (
           <button 
             onClick={() => moveLead(lead.id, 'Arquivado')}
             className="text-xs bg-gray-100 text-gray-500 px-3 py-1.5 rounded-lg font-bold"
           >
             Arquivar
           </button>
         )}
         {/* Back button for logic flow */}
         {lead.status === 'Negociacao' && (
            <button onClick={() => moveLead(lead.id, 'Potencial')} className="p-1.5 text-gray-400 hover:bg-gray-100 rounded-lg">
               <span className="text-[10px]">Voltar</span>
            </button>
         )}
         {lead.status === 'Potencial' && (
            <button onClick={() => moveLead(lead.id, 'Negociacao')} className="text-xs bg-yellow-100 text-yellow-700 px-3 py-1.5 rounded-lg font-bold">
               Negociar
            </button>
         )}
      </div>
    </div>
  </motion.div>
);

