      {/* Mobile Tabs (Visible only on small screens) */}
      <div className="md:hidden flex justify-start gap-2 overflow-x-auto pb-4 no-scrollbar px-1 -mx-1 mask-linear-fade">
        {columns.map(col => (
          <button
            key={col.id}
            onClick={() => setActiveMobileTab(col.id)}
            className={`px-4 py-2 rounded-full text-xs font-bold whitespace-nowrap transition-all border flex-shrink-0 ${
              activeMobileTab === col.id 
