import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import MobileNav from './components/MobileNav';
import Header from './components/Header';
import DashboardHome from './components/DashboardHome';
import CRMView from './components/CRMView';
import TasksView from './components/TasksView';
import GoalsView from './components/GoalsView';
import AuthScreen from './components/AuthScreen';
import { ViewState, Task, Lead, Goal, User, DatabaseSchema } from './types';
import { motion, AnimatePresence } from 'framer-motion';
import { CheckCircle2, XCircle } from 'lucide-react';

// --- Database Helper Functions ---
const DB_KEY = 'vantage_db_v1';

const getDB = (): DatabaseSchema => {
  const stored = localStorage.getItem(DB_KEY);
  return stored ? JSON.parse(stored) : { users: {} };
};

const saveDB = (db: DatabaseSchema) => {
  localStorage.setItem(DB_KEY, JSON.stringify(db));
};

function App() {
  // --- Auth State ---
  const [user, setUser] = useState<User | null>(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isAuthChecking, setIsAuthChecking] = useState(true);

  // --- App State ---
  const [activeView, setActiveView] = useState<ViewState>('dashboard');
  const [tasks, setTasks] = useState<Task[]>([]);
  const [leads, setLeads] = useState<Lead[]>([]);
  const [goals, setGoals] = useState<Goal[]>([]);

  // --- Toast Notification State ---
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);

  // Show Toast Helper
  const showToast = (message: string, type: 'success' | 'error') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  // --- 1. Check Session on Load ---
  useEffect(() => {
    const db = getDB();
    if (db.lastUserEmail && db.users[db.lastUserEmail]) {
      const userData = db.users[db.lastUserEmail];
      setUser(userData.user);
      setIsAuthenticated(true);

      // Load Data
      setTasks(userData.data.tasks || []);
      setLeads(userData.data.leads || []);
      setGoals(userData.data.goals || []);
    }
    // Artificial delay for splash screen effect
    setTimeout(() => setIsAuthChecking(false), 500);
  }, []);

  // --- 2. Persist Data ONLY when Authenticated ---
  useEffect(() => {
    if (!isAuthenticated || !user) return;

    const db = getDB();
    if (db.users[user.email]) {
      db.users[user.email].data = { tasks, leads, goals };
      saveDB(db);
    }
  }, [tasks, leads, goals, isAuthenticated, user]);

  // --- Auth Handlers ---
  const handleLogin = (email: string, pass: string): boolean => {
    const db = getDB();
    const targetUser = db.users[email];

    if (targetUser && targetUser.password === pass) {
      setUser(targetUser.user);
      setTasks(targetUser.data.tasks);
      setLeads(targetUser.data.leads);
      setGoals(targetUser.data.goals);

      // Persist session
      db.lastUserEmail = email;
      saveDB(db);

      setIsAuthenticated(true);
      showToast(`Bem-vindo de volta, ${targetUser.user.name.split(' ')[0]}!`, 'success');
      return true;
    }
    return false;
  };

  const handleRegister = (name: string, email: string, pass: string): boolean => {
    const db = getDB();

    if (db.users[email]) {
      return false; // User exists
    }

    const newUser: User = { name, email };

    // Create new record
    db.users[email] = {
      password: pass,
      user: newUser,
      data: {
        tasks: [],
        leads: [],
        goals: []
      }
    };

    // Log them in immediately
    db.lastUserEmail = email;
    saveDB(db);

    setUser(newUser);
    setTasks([]);
    setLeads([]);
    setGoals([]);
    setIsAuthenticated(true);
    showToast('Conta criada com sucesso!', 'success');
    return true;
  };

  const handleLogout = () => {
    const db = getDB();
    db.lastUserEmail = undefined;
    saveDB(db);

    setIsAuthenticated(false);
    setUser(null);
    setTasks([]);
    setLeads([]);
    setGoals([]);
    showToast('Logout realizado.', 'success');
  };

  if (isAuthChecking) {
    return (
      <div className="h-screen w-screen bg-luxury-50 flex items-center justify-center">
         <div className="w-16 h-16 border-4 border-luxury-900/10 border-t-luxury-900 rounded-full animate-spin"></div>
      </div>
    );
  }

  if (!isAuthenticated) {
    return (
      <>
        <AuthScreen onLogin={handleLogin} onRegister={handleRegister} />
        <ToastContainer toast={toast} />
      </>
    );
  }

  return (
    <div className="flex h-screen bg-luxury-50 font-sans selection:bg-luxury-900 selection:text-white overflow-hidden">
      <Sidebar activeView={activeView} setView={setActiveView} onLogout={handleLogout} />

      <div className="flex-1 flex flex-col relative h-full">
        <Header title={activeView} />

        {/* Adjusted padding for mobile bottom nav + safe area. pb-28 ensures content clears the fixed nav */}
        <main className="flex-1 overflow-y-auto overflow-x-hidden p-4 md:p-8 scroll-smooth pb-28 lg:pb-8 pt-2">
          <div className="max-w-7xl mx-auto">
            <AnimatePresence mode="wait">
              <motion.div
                key={activeView}
                initial={{ opacity: 0, scale: 0.98 }}
                animate={{ opacity: 1, scale: 1 }}
                exit={{ opacity: 0, scale: 0.98 }}
                transition={{ duration: 0.2 }}
              >
                {activeView === 'dashboard' && (
                  <DashboardHome 
                    tasks={tasks}
                    setTasks={setTasks} 
                    leads={leads} 
                    goals={goals} 
                  />
                )}
                {activeView === 'crm' && (
                  <CRMView 
                    leads={leads} 
                    setLeads={setLeads} 
                    tasks={tasks}
                    setTasks={setTasks}
                  />
                )}
                {activeView === 'tasks' && (
                  <TasksView tasks={tasks} setTasks={setTasks} />
                )}
                {activeView === 'goals' && (
                  <GoalsView goals={goals} setGoals={setGoals} />
                )}
              </motion.div>
            </AnimatePresence>
          </div>
        </main>

        <MobileNav activeView={activeView} setView={setActiveView} />

        {/* Toast Container (Always visible) */}
        <ToastContainer toast={toast} />
      </div>
    </div>
  );
}

// Simple Toast Component placed at root
const ToastContainer = ({ toast }: { toast: { message: string, type: 'success' | 'error' } | null }) => {
  return (
    <AnimatePresence>
      {toast && (
        <motion.div 
          initial={{ opacity: 0, y: -50, x: '-50%' }}
          animate={{ opacity: 1, y: 20, x: '-50%' }}
          exit={{ opacity: 0, y: -50, x: '-50%' }}
          className={`fixed top-0 left-1/2 z-[200] px-6 py-3 rounded-full shadow-2xl flex items-center gap-3 border ${
            toast.type === 'success' 
              ? 'bg-luxury-900 text-white border-luxury-800' 
              : 'bg-white text-red-600 border-red-100'
          }`}
        >
          {toast.type === 'success' ? <CheckCircle2 size={18} className="text-green-400" /> : <XCircle size={18} />}
          <span className="font-semibold text-sm">{toast.message}</span>
        </motion.div>
      )}
    </AnimatePresence>
  );
};

