               <h2 className="text-lg md:text-2xl font-bold tracking-tight truncate">
                 R$ {monthlyRevenue.toLocaleString('pt-BR', { notation: "compact", maximumFractionDigits: 1 })}
               </h2>
             </div>
          </div>

          {/* Card 2: Active Clients */}
          <div className="flex items-center gap-3 p-3 bg-white/5 rounded-xl border border-white/10">
              <div className="p-2 bg-white/10 rounded-lg text-blue-400 shrink-0">
                 <Users size={18} />
              </div>
              <div className="min-w-0 flex-1">
                <p className="text-gray-400 text-[10px] uppercase font-bold truncate">Ativos</p>
                <h2 className="text-lg md:text-2xl font-bold truncate">{activeClientsCount}</h2>
              </div>
           </div>
