interface CRMViewProps {
  leads: Lead[];
  setLeads: React.Dispatch<React.SetStateAction<Lead[]>>;
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
}

const CRMView: React.FC<CRMViewProps> = ({ leads, setLeads, tasks, setTasks }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newLead, setNewLead] = useState<Partial<Lead>>({ status: 'Potencial' });
  const [activeMobileTab, setActiveMobileTab] = useState<Lead['status']>('Ativo'); // Default view on mobile

  // Notes State
  const [editingNoteLead, setEditingNoteLead] = useState<Lead | null>(null);
  const [noteText, setNoteText] = useState('');

  // Customized columns for Client Management
  const columns: { id: Lead['status']; label: string; color: string; bg: string }[] = [
    { id: 'Potencial', label: 'Interesse', color: 'bg-blue-500', bg: 'bg-blue-50' },
    { id: 'Negociacao', label: 'Negociando', color: 'bg-yellow-500', bg: 'bg-yellow-50' },
    { id: 'Ativo', label: 'Ativos', color: 'bg-green-500', bg: 'bg-green-100' },
    { id: 'Arquivado', label: 'Arquivados', color: 'bg-gray-400', bg: 'bg-gray-50' },
  ];

  // Calculate Monthly Recurring Revenue (MRR)
  const monthlyRevenue = leads
    .filter(l => l.status === 'Ativo')
    .reduce((acc, curr) => acc + curr.value, 0);

  const activeClientsCount = leads.filter(l => l.status === 'Ativo').length;

  const handleAddLead = () => {
    if (!newLead.name || !newLead.value) return;

    // 1. Create the Lead
    const lead: Lead = {
      id: Date.now().toString(),
      name: newLead.name,
      company: newLead.company || 'Pessoal',
      value: Number(newLead.value),
      status: 'Potencial',
      lastContact: new Date().toLocaleDateString('pt-BR'),
      phone: newLead.phone || '',
      notes: ''
    };

    // 2. Automatically create the Daily Optimization Task
    const newTask: Task = {
      id: `auto-task-${Date.now()}`,
      text: `Analisar/Otimizar campanhas: ${newLead.name}`,
      completed: false,
      date: new Date().toISOString().split('T')[0], // Today
      time: '09:00', // Default morning slot
      category: 'Trabalho'
    };

    setLeads([...leads, lead]);
    setTasks(prevTasks => [newTask, ...prevTasks]); // Add task to the list

    setIsModalOpen(false);
    setNewLead({ status: 'Potencial' });
  };

  const deleteLead = (id: string) => {
    setLeads(leads.filter(l => l.id !== id));
  };

  const moveLead = (id: string, newStatus: Lead['status']) => {
    setLeads(leads.map(l => l.id === id ? { ...l, status: newStatus } : l));
  };

  const openNoteModal = (lead: Lead) => {
    setEditingNoteLead(lead);
    setNoteText(lead.notes || '');
  };

  const saveNote = () => {
    if (editingNoteLead) {
      setLeads(leads.map(l => l.id === editingNoteLead.id ? { ...l, notes: noteText } : l));
      setEditingNoteLead(null);
      setNoteText('');
    }
  };

  return (
    <div className="h-full flex flex-col pb-safe w-full max-w-full overflow-hidden">
      {/* Summary Header - Compact Layout for Mobile */}
      <div className="bg-luxury-900 text-white rounded-2xl md:rounded-3xl p-4 md:p-6 mb-4 md:mb-6 shadow-xl flex flex-col gap-3 md:gap-6 relative overflow-hidden shrink-0 w-full">
        {/* Background Decoration */}
        <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-b from-white/5 to-transparent pointer-events-none" />

        <div className="grid grid-cols-2 w-full gap-2 md:gap-4 relative z-10">
          {/* Card 1: MRR */}
          <div className="flex items-center gap-2 md:gap-3 p-2.5 md:p-3 bg-white/5 rounded-xl border border-white/10 min-w-0">
             <div className="p-1.5 md:p-2 bg-white/10 rounded-lg text-green-400 shrink-0">
               <Wallet size={16} className="md:w-[18px] md:h-[18px]" />
             </div>
             <div className="min-w-0 flex-1">
               <p className="text-gray-400 text-[10px] uppercase tracking-wide font-bold truncate">MRR</p>
               <h2 className="text-lg md:text-2xl font-bold tracking-tight truncate">
                 R$ {monthlyRevenue.toLocaleString('pt-BR', { notation: "compact", maximumFractionDigits: 1 })}
               </h2>
             </div>
          </div>

          {/* Card 2: Active Clients */}
          <div className="flex items-center gap-2 md:gap-3 p-2.5 md:p-3 bg-white/5 rounded-xl border border-white/10 min-w-0">
              <div className="p-1.5 md:p-2 bg-white/10 rounded-lg text-blue-400 shrink-0">
                 <Users size={16} className="md:w-[18px] md:h-[18px]" />
              </div>
              <div className="min-w-0 flex-1">
                <p className="text-gray-400 text-[10px] uppercase font-bold truncate">Clientes Ativos</p>
                <h2 className="text-lg md:text-2xl font-bold truncate">{activeClientsCount}</h2>
              </div>
           </div>
        </div>

        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-white text-luxury-900 w-full py-2.5 md:py-3.5 rounded-xl flex items-center justify-center gap-2 hover:bg-gray-100 transition-colors font-bold shadow-lg active:scale-95 relative z-10 text-sm"
        >
          <Plus size={16} /> Novo Cliente
        </button>
      </div>

      {/* Mobile Tabs (Visible only on small screens) */}
      <div className="md:hidden flex justify-start gap-2 overflow-x-auto pb-4 no-scrollbar shrink-0 w-full">
        {columns.map(col => (
          <button
            key={col.id}
            onClick={() => setActiveMobileTab(col.id)}
            className={`px-4 py-2 rounded-full text-xs font-bold whitespace-nowrap transition-all border flex-shrink-0 ${
              activeMobileTab === col.id 
                ? 'bg-luxury-900 text-white border-luxury-900' 
                : 'bg-white text-gray-500 border-gray-200'
            }`}
          >
            {col.label} <span className="ml-1 opacity-70">({leads.filter(l => l.status === col.id).length})</span>
          </button>
        ))}
      </div>

      {/* Content Area */}
      <div className="flex-1 min-h-0 w-full">
        {/* Desktop View: Kanban (Grid) */}
        <div className="hidden md:flex gap-4 h-full pb-4 overflow-x-auto">
          {columns.map(col => (
             <Column 
               key={col.id} 
               col={col} 
               leads={leads} 
               moveLead={moveLead} 
               deleteLead={deleteLead} 
               openNoteModal={openNoteModal}
             />
          ))}
        </div>

        {/* Mobile View: Vertical List based on Tab */}
        <div className="md:hidden h-full w-full">
           <AnimatePresence mode="wait">
             <motion.div
               key={activeMobileTab}
               initial={{ opacity: 0, y: 10 }}
               animate={{ opacity: 1, y: 0 }}
               exit={{ opacity: 0, y: -10 }}
               className="space-y-3 pb-20 w-full"
             >
               {leads.filter(l => l.status === activeMobileTab).length === 0 ? (
                 <div className="text-center py-12 text-gray-400 flex flex-col items-center">
                    <LayoutList size={32} className="mb-2 opacity-20" />
                    <p className="text-sm">Nenhum cliente nesta etapa.</p>
                 </div>
               ) : (
                 leads.filter(l => l.status === activeMobileTab).map(lead => (
                   <LeadCard 
                     key={lead.id} 
                     lead={lead} 
                     moveLead={moveLead} 
                     deleteLead={deleteLead} 
                     isMobile={true}
                     openNoteModal={openNoteModal}
                   />
                 ))
               )}
             </motion.div>
           </AnimatePresence>
        </div>
      </div>

      {/* Add Lead Modal */}
      <AnimatePresence>
        {isModalOpen && (
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-[100] bg-black/40 backdrop-blur-sm flex items-center justify-center p-4"
          >
            <motion.div 
              initial={{ scale: 0.9, y: 20 }} animate={{ scale: 1, y: 0 }}
              className="bg-white rounded-3xl w-[95%] max-w-md p-6 shadow-2xl"
            >
              <h3 className="text-xl font-bold mb-4">Adicionar Lead</h3>
              <div className="space-y-4">
                <input 
                  className="w-full p-4 bg-gray-50 rounded-xl border border-gray-200 outline-none focus:border-luxury-900 transition-colors"
                  placeholder="Nome do Cliente"
                  value={newLead.name || ''}
                  onChange={e => setNewLead({...newLead, name: e.target.value})}
                />
                <input 
                  className="w-full p-4 bg-gray-50 rounded-xl border border-gray-200 outline-none focus:border-luxury-900 transition-colors"
                  placeholder="Serviço (ex: Consultoria)"
                  value={newLead.company || ''}
                  onChange={e => setNewLead({...newLead, company: e.target.value})}
                />
                <div className="relative">
                   <span className="absolute left-4 top-4 text-gray-400 text-sm font-bold">R$</span>
                   <input 
                    type="number"
                    className="w-full p-4 pl-10 bg-gray-50 rounded-xl border border-gray-200 outline-none focus:border-luxury-900 transition-colors font-mono"
                    placeholder="Valor Mensal"
                    value={newLead.value || ''}
                    onChange={e => setNewLead({...newLead, value: Number(e.target.value)})}
                  />
                </div>
              </div>
              <div className="flex justify-end gap-3 mt-6">
                <button onClick={() => setIsModalOpen(false)} className="px-4 py-3 text-gray-500 hover:text-gray-800 font-medium text-sm">Cancelar</button>
                <button onClick={handleAddLead} className="px-6 py-3 bg-luxury-900 text-white rounded-xl font-bold hover:bg-black shadow-lg shadow-luxury-900/20 text-sm">Salvar</button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Notes Modal - Enhanced UI */}
      <AnimatePresence>
        {editingNoteLead && (
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-[110] bg-black/40 backdrop-blur-sm flex items-center justify-center p-4"
          >
            <motion.div 
              initial={{ scale: 0.95, y: 20 }} animate={{ scale: 1, y: 0 }}
              className="bg-white rounded-3xl w-full max-w-2xl p-6 md:p-8 shadow-2xl flex flex-col h-[85vh] md:h-[650px]"
            >
              <div className="flex justify-between items-center mb-6 flex-shrink-0">
                <div>
                   <h3 className="text-xl md:text-2xl font-bold text-luxury-900 truncate max-w-[200px] md:max-w-md">Anotações do Cliente</h3>
                   <p className="text-gray-500 text-xs md:text-sm mt-1 flex items-center gap-2 truncate">
                      <Users size={12} /> {editingNoteLead.name} 
                      <span className="w-1 h-1 rounded-full bg-gray-300"></span> 
                      {editingNoteLead.company}
                   </p>
                </div>
                <button 
                  onClick={() => setEditingNoteLead(null)}
                  className="p-2 rounded-full hover:bg-gray-100 text-gray-400 hover:text-gray-600 transition-colors flex-shrink-0"
                >
                  <X size={24} />
                </button>
              </div>

              <div className="flex-1 relative flex flex-col min-h-0">
                <textarea 
                  className="flex-1 w-full p-6 bg-gray-50 rounded-2xl border border-gray-100 focus:border-luxury-200 focus:bg-white focus:ring-4 focus:ring-luxury-50 outline-none transition-all resize-none text-gray-700 leading-relaxed text-base md:text-lg mb-2"
                  placeholder="Digite aqui os detalhes importantes, histórico de conversas ou próximas ações..."
                  value={noteText}
                  onChange={e => setNoteText(e.target.value)}
                  autoFocus
                />
              </div>

              <div className="flex flex-col md:flex-row justify-between items-center mt-4 pt-4 border-t border-gray-100 flex-shrink-0 gap-4">
                <span className="text-xs text-gray-400 font-medium order-2 md:order-1">
                   {noteText.length} caracteres
                </span>
                <div className="flex gap-3 w-full md:w-auto order-1 md:order-2">
                    <button 
                       onClick={() => setEditingNoteLead(null)} 
                       className="flex-1 md:flex-none px-6 py-3 text-gray-500 hover:text-luxury-900 font-semibold text-sm rounded-xl hover:bg-gray-50 transition-colors"
                    >
                      Cancelar
                    </button>
                    <button 
                       onClick={saveNote} 
                       className="flex-1 md:flex-none px-8 py-3 bg-luxury-900 text-white rounded-xl font-bold hover:bg-black hover:shadow-lg hover:-translate-y-0.5 active:translate-y-0 transition-all text-sm flex items-center justify-center gap-2"
                    >
                      <FileText size={18} />
                      Salvar Notas
                    </button>
                </div>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

// Subcomponents for cleaner code
const Column = ({ col, leads, moveLead, deleteLead, openNoteModal }: any) => (
  <div className={`min-w-[85vw] md:min-w-[320px] flex-1 flex flex-col rounded-3xl p-4 border ${col.id === 'Ativo' ? 'bg-green-50/50 border-green-100' : 'bg-gray-50 border-gray-100'}`}>
    <div className="flex items-center gap-2 mb-4 px-2">
      <div className={`w-3 h-3 rounded-full ${col.color}`} />
      <span className={`font-bold ${col.id === 'Ativo' ? 'text-green-800' : 'text-gray-700'}`}>{col.label}</span>
      <span className="ml-auto text-xs font-bold text-gray-500 bg-white px-2 py-1 rounded-full shadow-sm">
        {leads.filter((l: Lead) => l.status === col.id).length}
      </span>
    </div>
    <div className="flex-1 space-y-3 overflow-y-auto scrollbar-thin custom-scrollbar pr-1">
      {leads.filter((l: Lead) => l.status === col.id).map((lead: Lead) => (
        <LeadCard key={lead.id} lead={lead} moveLead={moveLead} deleteLead={deleteLead} openNoteModal={openNoteModal} />
      ))}
    </div>
  </div>
);

const LeadCard = ({ lead, moveLead, deleteLead, isMobile, openNoteModal }: any) => (
  <motion.div 
    layoutId={lead.id}
    className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 active:scale-98 transition-transform group relative w-full"
  >
    <div className="flex justify-between items-start mb-1 gap-2">
      <span className="font-bold text-luxury-900 text-base truncate flex-1 min-w-0">{lead.name}</span>
      <div className="flex gap-1 flex-shrink-0">
        <button 
          onClick={(e) => { e.stopPropagation(); openNoteModal(lead); }} 
          className={`p-1.5 rounded-lg transition-colors ${lead.notes ? 'text-yellow-500 bg-yellow-50 hover:bg-yellow-100' : 'text-gray-300 hover:text-gray-500 hover:bg-gray-50'}`}
          title="Anotações"
        >
          <FileText size={16} />
        </button>
        <button onClick={() => deleteLead(lead.id)} className="text-gray-300 hover:text-red-500 p-1.5 hover:bg-red-50 rounded-lg">
          <Trash2 size={16} />
        </button>
      </div>
    </div>
    <div className="flex items-center gap-1 text-xs text-gray-500 mb-3 truncate">
      <Building2 size={12} className="flex-shrink-0" />
      <span className="truncate">{lead.company}</span>
    </div>

    {/* Refactored Footer: Responsive Layout */}
    <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center pt-3 border-t border-gray-50 gap-3">
      <div className="flex flex-col">
        <span className="text-[10px] text-gray-400 uppercase font-bold">Mensal</span>
        <span className="font-mono font-bold text-luxury-900 text-sm">
          {lead.value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 })}
        </span>
      </div>

      {/* Contextual Actions - Wrapped for safety */}
      <div className="flex gap-2 flex-wrap justify-end sm:justify-end">
         {lead.status !== 'Ativo' && (
           <button 
             onClick={() => moveLead(lead.id, 'Ativo')}
             className="text-xs bg-luxury-900 text-white px-3 py-1.5 rounded-lg font-bold shadow-md shadow-luxury-900/10 whitespace-nowrap flex-1 sm:flex-none justify-center flex"
           >
             Fechar
           </button>
         )}
         {lead.status === 'Ativo' && (
           <button 
             onClick={() => moveLead(lead.id, 'Arquivado')}
             className="text-xs bg-gray-100 text-gray-500 px-3 py-1.5 rounded-lg font-bold whitespace-nowrap flex-1 sm:flex-none justify-center flex"
           >
             Arquivar
           </button>
         )}
         {lead.status === 'Negociacao' && (
            <button onClick={() => moveLead(lead.id, 'Potencial')} className="p-1.5 text-gray-400 hover:bg-gray-100 rounded-lg whitespace-nowrap flex-1 sm:flex-none justify-center flex">
               <span className="text-[10px]">Voltar</span>
            </button>
         )}
         {lead.status === 'Potencial' && (
            <button onClick={() => moveLead(lead.id, 'Negociacao')} className="text-xs bg-yellow-100 text-yellow-700 px-3 py-1.5 rounded-lg font-bold whitespace-nowrap flex-1 sm:flex-none justify-center flex">
               Negociar
            </button>
         )}
      </div>
    </div>
  </motion.div>
);

export default CRMView;

import React, { useState } from 'react';
import { Plus, Building2, Trash2, Wallet, Users, LayoutList, FileText, X } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Lead, Task } from '../types';

interface CRMViewProps {
  leads: Lead[];
  setLeads: React.Dispatch<React.SetStateAction<Lead[]>>;
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
}

const CRMView: React.FC<CRMViewProps> = ({ leads, setLeads, tasks, setTasks }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newLead, setNewLead] = useState<Partial<Lead>>({ status: 'Potencial' });
  const [activeMobileTab, setActiveMobileTab] = useState<Lead['status']>('Ativo'); // Default view on mobile

