  const [editingNoteLead, setEditingNoteLead] = useState<Lead | null>(null);
  const [noteText, setNoteText] = useState('');

  // Customized columns for Client Management
  const columns: { id: Lead['status']; label: string; color: string; bg: string }[] = [
    { id: 'Potencial', label: 'Interesse', color: 'bg-blue-500', bg: 'bg-blue-50' },
    { id: 'Negociacao', label: 'Negociando', color: 'bg-yellow-500', bg: 'bg-yellow-50' },
    { id: 'Ativo', label: 'Ativos', color: 'bg-green-500', bg: 'bg-green-100' },
    { id: 'Arquivado', label: 'Arquivados', color: 'bg-gray-400', bg: 'bg-gray-50' },
  ];

  // Calculate Monthly Recurring Revenue (MRR)
  const monthlyRevenue = leads
    .filter(l => l.status === 'Ativo')
    .reduce((acc, curr) => acc + curr.value, 0);

  const activeClientsCount = leads.filter(l => l.status === 'Ativo').length;

  const handleAddLead = () => {
    if (!newLead.name || !newLead.value) return;

    // 1. Create the Lead
    const lead: Lead = {
      id: Date.now().toString(),
      name: newLead.name,
      company: newLead.company || 'Pessoal',
      value: Number(newLead.value),
      status: 'Potencial',
      lastContact: new Date().toLocaleDateString('pt-BR'),
      phone: newLead.phone || '',
      notes: ''
    };

    // 2. Automatically create the Daily Optimization Task
    const newTask: Task = {
      id: `auto-task-${Date.now()}`,
      text: `Analisar/Otimizar campanhas: ${newLead.name}`,
      completed: false,
      date: new Date().toISOString().split('T')[0], // Today
      time: '09:00', // Default morning slot
      category: 'Trabalho'
    };

    setLeads([...leads, lead]);
    setTasks(prevTasks => [newTask, ...prevTasks]); // Add task to the list

    setIsModalOpen(false);
    setNewLead({ status: 'Potencial' });
  };

  const deleteLead = (id: string) => {
    setLeads(leads.filter(l => l.id !== id));
  };

  const moveLead = (id: string, newStatus: Lead['status']) => {
    setLeads(leads.map(l => l.id === id ? { ...l, status: newStatus } : l));
  };

  const openNoteModal = (lead: Lead) => {
    setEditingNoteLead(lead);
    setNoteText(lead.notes || '');
  };

  const saveNote = () => {
    if (editingNoteLead) {
      setLeads(leads.map(l => l.id === editingNoteLead.id ? { ...l, notes: noteText } : l));
      setEditingNoteLead(null);
      setNoteText('');
    }
  };

  return (
    <div className="h-full flex flex-col pb-safe w-full max-w-full overflow-hidden">
      {/* Summary Header - Fixed Mobile Overflow by Stacking */}
      <div className="bg-luxury-900 text-white rounded-2xl md:rounded-3xl p-5 md:p-6 mb-4 md:mb-6 shadow-xl flex flex-col gap-4 md:gap-6 relative overflow-hidden shrink-0 w-full">
        {/* Background Decoration */}
        <div className="absolute top-0 left-0 w-full h-full bg-gradient-to-b from-white/5 to-transparent pointer-events-none" />

        {/* Stats Grid: Stacks vertically on mobile (grid-cols-1), side-by-side on desktop (md:grid-cols-2) */}
        <div className="grid grid-cols-1 md:grid-cols-2 w-full gap-3 md:gap-4 relative z-10">
          {/* Card 1: MRR */}
          <div className="flex items-center gap-3 p-3 bg-white/5 rounded-xl border border-white/10 w-full min-w-0">
             <div className="p-2 bg-white/10 rounded-lg text-green-400 shrink-0">
               <Wallet size={18} className="md:w-[20px] md:h-[20px]" />
