             </div>
          </div>

          {/* Card 2: Active Clients */}
          <div className="flex items-center gap-3 p-3 bg-white/5 rounded-xl border border-white/10 w-full min-w-0">
              <div className="p-2 bg-white/10 rounded-lg text-blue-400 shrink-0">
                 <Users size={18} className="md:w-[20px] md:h-[20px]" />
