              <div className="min-w-0 flex-1">
                <p className="text-gray-400 text-[10px] uppercase font-bold truncate">Clientes Ativos</p>
                <h2 className="text-xl md:text-2xl font-bold truncate">{activeClientsCount}</h2>
              </div>
           </div>
        </div>

        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-white text-luxury-900 w-full py-3 md:py-3.5 rounded-xl flex items-center justify-center gap-2 hover:bg-gray-100 transition-colors font-bold shadow-lg active:scale-95 relative z-10 text-sm"
        >
