                ? 'bg-luxury-900 text-white border-luxury-900' 
                : 'bg-white text-gray-500 border-gray-200'
            }`}
          >
            {col.label} <span className="ml-1 opacity-70">({leads.filter(l => l.status === col.id).length})</span>
          </button>
        ))}
      </div>

      {/* Content Area */}
      <div className="flex-1 min-h-0 w-full">
        {/* Desktop View: Kanban (Grid) */}
        <div className="hidden md:flex gap-4 h-full pb-4 overflow-x-auto">
          {columns.map(col => (
             <Column 
               key={col.id} 
