      {/* Add Lead Modal - UPDATED INPUTS */}
      <AnimatePresence>
        {isModalOpen && (
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-[100] bg-black/40 backdrop-blur-sm flex items-center justify-center p-4"
          >
            <motion.div 
              initial={{ scale: 0.9, y: 20 }} animate={{ scale: 1, y: 0 }}
              className="bg-white rounded-3xl w-[95%] max-w-md p-6 shadow-2xl relative"
            >
              <div className="flex justify-between items-center mb-6">
                 <h3 className="text-xl font-bold text-luxury-900">Novo Cliente</h3>
                 <button onClick={() => setIsModalOpen(false)} className="p-1 rounded-full hover:bg-gray-100 text-gray-400"><X size={20} /></button>
              </div>

              <div className="space-y-4">
                <div className="space-y-1">
                   <label className="text-xs font-bold text-gray-500 ml-1">Nome Completo</label>
                   <div className="relative">
                      <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                        <User size={18} />
                      </div>
                      <input 
                        className="w-full pl-10 pr-4 py-3.5 bg-gray-50 border border-gray-200 rounded-xl outline-none focus:border-luxury-900 focus:bg-white focus:ring-2 focus:ring-luxury-900/5 transition-all text-sm font-medium text-gray-900 placeholder:text-gray-400"
                        placeholder="Ex: Roberto Almeida"
                        value={newLead.name || ''}
                        onChange={e => setNewLead({...newLead, name: e.target.value})}
                      />
                   </div>
                </div>

                <div className="space-y-1">
                   <label className="text-xs font-bold text-gray-500 ml-1">Serviço / Empresa</label>
                   <div className="relative">
                      <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-gray-400">
                        <Building2 size={18} />
                      </div>
                      <input 
                        className="w-full pl-10 pr-4 py-3.5 bg-gray-50 border border-gray-200 rounded-xl outline-none focus:border-luxury-900 focus:bg-white focus:ring-2 focus:ring-luxury-900/5 transition-all text-sm font-medium text-gray-900 placeholder:text-gray-400"
                        placeholder="Ex: Consultoria Mensal"
                        value={newLead.company || ''}
                        onChange={e => setNewLead({...newLead, company: e.target.value})}
                      />
                   </div>
                </div>

                <div className="space-y-1">
                   <label className="text-xs font-bold text-gray-500 ml-1">Valor Mensal (Recorrência)</label>
                   <div className="relative">
                      <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-green-600">
                        <DollarSign size={18} />
                      </div>
                      <input 
                        type="number"
                        className="w-full pl-10 pr-4 py-3.5 bg-gray-50 border border-gray-200 rounded-xl outline-none focus:border-luxury-900 focus:bg-white focus:ring-2 focus:ring-luxury-900/5 transition-all text-lg font-bold font-mono text-gray-900 placeholder:text-gray-400"
                        placeholder="0,00"
                        value={newLead.value || ''}
                        onChange={e => setNewLead({...newLead, value: Number(e.target.value)})}
                      />
                      <div className="absolute inset-y-0 right-4 flex items-center pointer-events-none text-gray-400 text-xs font-bold">BRL</div>
                   </div>
                </div>
              </div>

              <div className="flex justify-end gap-3 mt-8 pt-4 border-t border-gray-100">
                <button onClick={() => setIsModalOpen(false)} className="px-5 py-3 text-gray-500 hover:text-gray-900 font-semibold text-sm transition-colors">Cancelar</button>
                <button onClick={handleAddLead} className="px-8 py-3 bg-luxury-900 text-white rounded-xl font-bold hover:bg-black shadow-lg shadow-luxury-900/20 text-sm active:scale-95 transition-transform">Confirmar</button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Notes Modal */}
      <AnimatePresence>
        {editingNoteLead && (
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-[110] bg-black/40 backdrop-blur-sm flex items-center justify-center p-4"
          >
            <motion.div 
              initial={{ scale: 0.95, y: 20 }} animate={{ scale: 1, y: 0 }}
              className="bg-white rounded-3xl w-full max-w-2xl p-6 md:p-8 shadow-2xl flex flex-col h-[85vh] md:h-[650px]"
            >
              <div className="flex justify-between items-center mb-6 flex-shrink-0">
                <div>
                   <h3 className="text-xl md:text-2xl font-bold text-luxury-900 truncate max-w-[200px] md:max-w-md">Anotações do Cliente</h3>
                   <p className="text-gray-500 text-xs md:text-sm mt-1 flex items-center gap-2 truncate">
                      <Users size={12} /> {editingNoteLead.name} 
                      <span className="w-1 h-1 rounded-full bg-gray-300"></span> 
                      {editingNoteLead.company}
                   </p>
                </div>
                <button 
                  onClick={() => setEditingNoteLead(null)}
                  className="p-2 rounded-full hover:bg-gray-100 text-gray-400 hover:text-gray-600 transition-colors flex-shrink-0"
                >
                  <X size={24} />
                </button>
              </div>

              <div className="flex-1 relative flex flex-col min-h-0">
                <textarea 
                  className="flex-1 w-full p-6 bg-gray-50 rounded-2xl border border-gray-100 focus:border-luxury-200 focus:bg-white focus:ring-4 focus:ring-luxury-50 outline-none transition-all resize-none text-gray-700 leading-relaxed text-base md:text-lg mb-2"
                  placeholder="Digite aqui os detalhes importantes, histórico de conversas ou próximas ações..."
                  value={noteText}
                  onChange={e => setNoteText(e.target.value)}
                  autoFocus
                />
              </div>

              <div className="flex flex-col md:flex-row justify-between items-center mt-4 pt-4 border-t border-gray-100 flex-shrink-0 gap-4">
                <span className="text-xs text-gray-400 font-medium order-2 md:order-1">
                   {noteText.length} caracteres
                </span>
                <div className="flex gap-3 w-full md:w-auto order-1 md:order-2">
