import React, { useState, useEffect, useRef } from 'react';
import { Plus, Check, Clock, Calendar as CalendarIcon, Trash2, Briefcase, Dumbbell, Bell, Zap, CornerDownLeft } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Task } from '../types';

interface TasksViewProps {
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
}

const TasksView: React.FC<TasksViewProps> = ({ tasks, setTasks }) => {
  const [filter, setFilter] = useState<'all' | 'today' | 'pending'>('all');
  const [newTaskText, setNewTaskText] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<Task['category']>('Trabalho');
  const [showSuccess, setShowSuccess] = useState(false);

  // Notification States
  const [permission, setPermission] = useState<NotificationPermission>('default');
  const notifiedTasks = useRef(new Set<string>());

  const today = new Date().toISOString().split('T')[0];

  // --- Notification System ---
  useEffect(() => {
    if ('Notification' in window) {
      setPermission(Notification.permission);
    }

    const checkReminders = () => {
      if (!('Notification' in window) || Notification.permission !== 'granted') return;

      const now = new Date();

      tasks.forEach(task => {
        if (task.completed || notifiedTasks.current.has(task.id)) return;

        // Parse task datetime
        // Assuming task.date is YYYY-MM-DD and task.time is HH:MM
        const taskDateTime = new Date(`${task.date}T${task.time}`);

        // Calculate difference in minutes
        const diffMs = taskDateTime.getTime() - now.getTime();
        const diffMinutes = Math.floor(diffMs / 60000);

        // Notify if:
        // 1. Exactly 10 minutes remaining (Warning)
        // 2. Or if it's strictly "Now" (0 to 1 min late)
        if ((diffMinutes <= 10 && diffMinutes >= 0) || (diffMinutes < 0 && diffMinutes > -2)) {
          try {
            // Send Notification to Device
            const notif = new Notification(`Vantage: ${task.category}`, {
              body: diffMinutes <= 0 ? `HORA DE FAZER: ${task.text}` : `Faltam ${diffMinutes} min: "${task.text}"`,
              icon: 'https://cdn-icons-png.flaticon.com/512/3135/3135715.png', // Fallback icon
              tag: task.id, // Prevent duplicate notifications on Android
              renotify: true,
              silent: false,
            } as any);

            // Vibrate device if supported
            if (navigator.vibrate) navigator.vibrate([200, 100, 200]);

            // Mark as notified so we don't spam every minute
            notifiedTasks.current.add(task.id);
          } catch (error) {
            console.error("Erro notificação:", error);
          }
        }
      });
    };

    // Check immediately and every minute
    checkReminders();
    const interval = setInterval(checkReminders, 60000);
    return () => clearInterval(interval);
  }, [tasks]);

  const requestNotificationPermission = async () => {
    if (!('Notification' in window)) {
      alert("Este navegador não suporta notificações.");
      return;
    }
    const result = await Notification.requestPermission();
    setPermission(result);
    if (result === 'granted') {
      new Notification("Vantage Ativo", { body: "Notificações configuradas com sucesso!" });
    }
  };

  const handleAddTask = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTaskText.trim()) return;

    const newTask: Task = {
      id: Date.now().toString(),
      text: newTaskText,
      completed: false,
      date: today,
      time: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
      category: selectedCategory
    };

    setTasks([newTask, ...tasks]);
    setNewTaskText('');

    setShowSuccess(true);
    setTimeout(() => setShowSuccess(false), 1500);
  };

  const toggleTask = (id: string) => {
    setTasks(tasks.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  };

  const deleteTask = (id: string) => {
    setTasks(tasks.filter(t => t.id !== id));
  };

  const filteredTasks = tasks.filter(t => {
    if (filter === 'today') return t.date === today;
    if (filter === 'pending') return !t.completed;
    return true;
  });

  const getCategoryIcon = (cat: Task['category']) => {
    switch (cat) {
      case 'Academia': return <Dumbbell size={14} />;
      case 'Trabalho': return <Briefcase size={14} />;
      case 'Lembrete': return <Bell size={14} />;
    }
  };

  const getCategoryColor = (cat: Task['category']) => {
    switch (cat) {
      case 'Academia': return 'bg-orange-100 text-orange-700 border-orange-200';
      case 'Trabalho': return 'bg-blue-100 text-blue-700 border-blue-200';
      case 'Lembrete': return 'bg-purple-100 text-purple-700 border-purple-200';
    }
  };

  return (
    <div className="max-w-4xl mx-auto pb-24">
      <div className="mb-8 flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-luxury-900 mb-1">Rotina Diária</h2>
          <p className="text-gray-500">Organize trabalho, treinos e lembretes.</p>
        </div>

        {/* Notification Permission Button */}
        {permission !== 'granted' && 'Notification' in window && (
          <button 
            onClick={requestNotificationPermission}
            className="flex items-center gap-2 text-xs font-bold bg-luxury-900 text-white px-4 py-2 rounded-full shadow-lg hover:bg-black transition-colors animate-bounce"
          >
            <Bell size={14} /> Ativar Notificações
          </button>
        )}

        {permission === 'granted' && (
           <div className="flex items-center gap-1.5 text-xs font-bold text-green-600 bg-green-50 px-3 py-1.5 rounded-full border border-green-100">
             <Check size={12} /> Notificações Ativas
           </div>
        )}
      </div>

      {/* Premium Input Area */}
      <form onSubmit={handleAddTask} className="relative mb-8 group">
        <div className="absolute -inset-0.5 bg-gradient-to-r from-gray-200 to-gray-100 rounded-2xl blur opacity-30 group-hover:opacity-60 transition duration-500"></div>
        <div className="relative bg-white p-2 rounded-2xl shadow-soft border border-gray-100 flex flex-col md:flex-row gap-2">

          <div className="flex-1 relative">
            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
              <Zap size={18} className="text-luxury-900" />
            </div>
            <input 
              type="text" 
              value={newTaskText}
              onChange={(e) => setNewTaskText(e.target.value)}
              placeholder="Digite uma nova tarefa..." 
              className="w-full h-12 md:h-14 pl-11 pr-4 bg-transparent outline-none text-gray-800 placeholder:text-gray-400 font-medium text-base md:text-lg"
            />
          </div>

          <div className="flex items-center gap-2 px-2 pb-2 md:pb-0 justify-between md:justify-end border-t md:border-t-0 border-gray-50 pt-2 md:pt-0">
             <div className="flex gap-1">
              {(['Trabalho', 'Academia', 'Lembrete'] as Task['category'][]).map(cat => (
                <button
                  key={cat}
                  type="button"
                  onClick={() => setSelectedCategory(cat)}
                  className={`p-2 md:px-3 md:py-2 rounded-xl text-xs font-bold transition-all flex items-center gap-2 ${
                    selectedCategory === cat 
                      ? 'bg-luxury-900 text-white shadow-md' 
                      : 'bg-gray-50 text-gray-500 hover:bg-gray-100'
                  }`}
                  title={cat}
                >
                  {cat === 'Academia' && <Dumbbell size={14} />}
                  {cat === 'Trabalho' && <Briefcase size={14} />}
                  {cat === 'Lembrete' && <Bell size={14} />}
                  <span className="hidden md:inline">{cat}</span>
                </button>
              ))}
            </div>

            <button 
              type="submit"
              disabled={showSuccess}
              className={`h-10 md:h-12 px-4 md:px-6 rounded-xl flex items-center justify-center gap-2 transition-all duration-300 shadow-lg ${
                showSuccess 
                  ? 'bg-green-500 text-white shadow-green-500/30' 
                  : 'bg-luxury-900 text-white hover:bg-black shadow-luxury-900/20'
              }`}
            >
              <AnimatePresence mode="wait" initial={false}>
                {showSuccess ? (
                  <motion.div
                    key="check"
                    initial={{ scale: 0 }} animate={{ scale: 1 }} exit={{ scale: 0 }}
                  >
                    <Check size={20} />
                  </motion.div>
                ) : (
                  <motion.div
                    key="plus"
                    className="flex items-center gap-2 font-bold text-sm"
                    initial={{ scale: 0.8 }} animate={{ scale: 1 }} exit={{ scale: 0.8 }}
                  >
                    <span className="hidden md:inline">Adicionar</span>
                    <CornerDownLeft size={16} />
                  </motion.div>
                )}
              </AnimatePresence>
            </button>
          </div>
        </div>
      </form>

      {/* Filters */}
      <div className="flex gap-2 mb-6 overflow-x-auto pb-2 no-scrollbar">
        {['all', 'today', 'pending'].map((f) => (
          <button
            key={f}
            onClick={() => setFilter(f as any)}
            className={`px-5 py-2.5 rounded-full text-sm font-bold transition-all whitespace-nowrap ${
              filter === f 
                ? 'bg-luxury-900 text-white shadow-lg shadow-luxury-900/10' 
                : 'bg-white text-gray-400 hover:text-gray-600 border border-gray-100 hover:border-gray-200'
            }`}
          >
            {f === 'all' ? 'Todas' : f === 'today' ? 'Hoje' : 'Pendentes'}
          </button>
        ))}
      </div>

      {/* Task List */}
      <div className="space-y-3">
        <AnimatePresence mode="popLayout">
          {filteredTasks.length === 0 ? (
            <motion.div 
              initial={{ opacity: 0 }} animate={{ opacity: 1 }}
              className="text-center py-20 flex flex-col items-center justify-center bg-white/50 rounded-3xl border border-dashed border-gray-200"
            >
               <div className="bg-gray-100 p-4 rounded-full mb-4">
                 <Check size={32} className="text-gray-400" />
               </div>
               <p className="text-gray-500 font-medium">Tudo limpo por aqui.</p>
               <p className="text-xs text-gray-400 mt-1">Aproveite seu tempo livre.</p>
            </motion.div>
          ) : (
            filteredTasks.map((task) => (
              <motion.div
                layout
                key={task.id}
                initial={{ opacity: 0, scale: 0.98, y: 10 }}
                animate={{ opacity: 1, scale: 1, y: 0 }}
                exit={{ opacity: 0, scale: 0.98 }}
                className={`group flex items-center p-4 md:p-5 bg-white rounded-2xl border transition-all duration-300 ${
                  task.completed 
                    ? 'border-transparent bg-gray-50/80' 
                    : 'border-gray-100 hover:border-luxury-200 shadow-sm hover:shadow-md'
                }`}
              >
                <button 
                  onClick={() => toggleTask(task.id)}
                  className={`flex-shrink-0 w-6 h-6 rounded-lg border-2 flex items-center justify-center mr-4 transition-all duration-300 ${
                    task.completed 
                      ? 'bg-luxury-900 border-luxury-900' 
                      : 'border-gray-300 hover:border-luxury-900 bg-white group-hover:scale-110'
                  }`}
                >
                  {task.completed && <Check size={14} className="text-white" />}
                </button>

                <div className={`flex-1 transition-opacity duration-300 ${task.completed ? 'opacity-40' : 'opacity-100'}`}>
                  <p className={`text-base font-semibold ${task.completed ? 'text-gray-500 line-through decoration-gray-300' : 'text-gray-800'}`}>
                    {task.text}
                  </p>
                  <div className="flex flex-wrap items-center gap-3 mt-1.5">
                    <span className={`flex items-center gap-1.5 text-[10px] uppercase tracking-wider font-bold px-2 py-1 rounded-md border ${getCategoryColor(task.category)}`}>
                       {getCategoryIcon(task.category)} {task.category}
                    </span>
                    <span className="flex items-center gap-1 text-xs text-gray-400 font-medium bg-gray-50 px-2 py-1 rounded-md">
                       <Clock size={12} /> {task.time}
                    </span>
                  </div>
                </div>

                <button 
                  onClick={() => deleteTask(task.id)}
                  className="opacity-100 md:opacity-0 md:group-hover:opacity-100 p-2 text-gray-300 hover:text-red-500 hover:bg-red-50 rounded-lg transition-all"
                >
                  <Trash2 size={18} />
                </button>
              </motion.div>
            ))
          )}
        </AnimatePresence>
      </div>
    </div>
  );
};

