import React, { useState } from 'react';
import { Target, Plus, Zap, Trophy, Flame, Flag, Calendar, Hash } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Goal } from '../types';

interface GoalsViewProps {
  goals: Goal[];
  setGoals: React.Dispatch<React.SetStateAction<Goal[]>>;
}

const GoalsView: React.FC<GoalsViewProps> = ({ goals, setGoals }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newGoal, setNewGoal] = useState<Partial<Goal>>({});

  const handleAddGoal = () => {
    if (!newGoal.title || !newGoal.targetValue) return;
    const goal: Goal = {
      id: Date.now().toString(),
      title: newGoal.title,
      targetValue: Number(newGoal.targetValue),
      currentValue: Number(newGoal.currentValue) || 0,
      deadline: newGoal.deadline || '2024-12-31',
      unit: newGoal.unit || 'vezes'
    };
    setGoals([...goals, goal]);
    setIsModalOpen(false);
    setNewGoal({});
  };

  const updateProgress = (id: string, amount: number) => {
     setGoals(goals.map(g => {
       if (g.id === id) {
         const newVal = Math.min(g.targetValue, g.currentValue + amount);
         return { ...g, currentValue: newVal };
       }
       return g;
     }));
  };

  return (
    <div className="space-y-6 pb-20">
      <div className="flex flex-col md:flex-row md:justify-between md:items-end gap-4">
        <div>
           <h2 className="text-2xl md:text-3xl font-bold text-white tracking-tighter">Desafios</h2>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="bg-white text-black px-6 py-3 rounded font-bold hover:bg-gray-200 transition-all flex items-center justify-center gap-2 w-full md:w-auto uppercase tracking-wider text-sm"
        >
          <Plus size={16} /> Novo Desafio
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {goals.map((goal) => {
          const progress = Math.min(100, Math.round((goal.currentValue / goal.targetValue) * 100));
          const isCompleted = progress === 100;

          return (
            <motion.div 
              key={goal.id}
              initial={{ opacity: 0, scale: 0.95 }}
              animate={{ opacity: 1, scale: 1 }}
              className={`p-6 rounded-xl border flex flex-col relative overflow-hidden transition-all ${
                isCompleted 
                  ? 'bg-white text-black border-white' 
                  : 'bg-agency-900 border-agency-800'
              }`}
            >
              <div className="flex justify-between items-start mb-4 relative z-10">
                <div className={`p-2 rounded ${isCompleted ? 'bg-black text-white' : 'bg-black/50 text-white'}`}>
                  {isCompleted ? <Trophy size={18} /> : <Zap size={18} />}
                </div>
              </div>

              <h3 className={`text-xl font-bold mb-1 tracking-tight ${isCompleted ? 'text-black' : 'text-white'}`}>
                {goal.title}
              </h3>
              <p className={`text-xs font-mono mb-6 ${isCompleted ? 'text-gray-600' : 'text-gray-400'}`}>
                {goal.currentValue} / {goal.targetValue} {goal.unit}
              </p>

              <div className="mt-auto relative z-10">
                <div className={`h-1 w-full bg-gray-200/20 rounded-full mb-4 overflow-hidden`}>
                  <motion.div 
                    initial={{ width: 0 }}
                    animate={{ width: `${progress}%` }}
                    className={`h-full ${isCompleted ? 'bg-black' : 'bg-white'}`}
                  />
                </div>

                {!isCompleted ? (
                   <button 
                     onClick={() => updateProgress(goal.id, 1)}
                     className="w-full py-3 bg-black border border-agency-800 text-white rounded font-bold hover:bg-agency-900 transition-colors uppercase text-xs tracking-wider"
                   >
                     Registrar +1
                   </button>
                ) : (
                   <div className="py-2 text-center text-xs font-bold text-black border border-black/10 rounded bg-black/5 uppercase">
                     Concluído
                   </div>
                )}
              </div>
            </motion.div>
          );
        })}

        {goals.length === 0 && (
          <div 
            onClick={() => setIsModalOpen(true)}
            className="border border-dashed border-agency-800 rounded-xl flex flex-col items-center justify-center p-8 text-agency-sub hover:border-white hover:text-white cursor-pointer transition-all min-h-[250px] bg-agency-900/20"
          >
            <Flame size={48} className="mb-4 opacity-20" />
            <span className="font-bold uppercase tracking-wider text-sm">Criar Desafio</span>
          </div>
        )}
      </div>

       {/* Modal */}
       <AnimatePresence>
        {isModalOpen && (
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-sm flex items-center justify-center p-4"
          >
            <motion.div 
              initial={{ scale: 0.9 }} animate={{ scale: 1 }}
              className="bg-agency-900 border border-agency-800 rounded-xl w-[95%] max-w-sm p-6 shadow-2xl relative"
            >
              <h3 className="text-xl font-bold mb-6 text-white uppercase tracking-wide">Novo Desafio</h3>

              <div className="space-y-4">
                 <div className="space-y-1">
                    <label className="text-[10px] font-bold text-agency-sub uppercase tracking-widest">Objetivo</label>
                    <input className="w-full p-3 bg-black border border-agency-800 rounded outline-none text-white text-sm" placeholder="Ex: Correr 50km" value={newGoal.title || ''} onChange={e => setNewGoal({...newGoal, title: e.target.value})} />
                 </div>
                 <div className="flex gap-2">
                    <div className="flex-1 space-y-1">
                       <label className="text-[10px] font-bold text-agency-sub uppercase tracking-widest">Meta</label>
                       <input type="number" className="w-full p-3 bg-black border border-agency-800 rounded outline-none text-white text-sm font-mono" placeholder="50" value={newGoal.targetValue || ''} onChange={e => setNewGoal({...newGoal, targetValue: Number(e.target.value)})} />
                    </div>
                    <div className="flex-1 space-y-1">
                       <label className="text-[10px] font-bold text-agency-sub uppercase tracking-widest">Unidade</label>
                       <input className="w-full p-3 bg-black border border-agency-800 rounded outline-none text-white text-sm" placeholder="km" value={newGoal.unit || ''} onChange={e => setNewGoal({...newGoal, unit: e.target.value})} />
                    </div>
                 </div>
              </div>

              <div className="flex justify-end gap-3 mt-8 pt-4 border-t border-agency-800">
                <button onClick={() => setIsModalOpen(false)} className="px-5 py-3 text-agency-sub text-xs font-bold uppercase hover:text-white">Cancelar</button>
                <button onClick={handleAddGoal} className="px-6 py-3 bg-white text-black rounded font-bold hover:bg-gray-200 text-xs uppercase tracking-wide">Criar</button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

export default GoalsView;

import React, { useState } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { ArrowRight, Mail, Lock, User, AlertCircle } from 'lucide-react';

interface AuthScreenProps {
  onLogin: (email: string, pass: string) => boolean;
  onRegister: (name: string, email: string, pass: string) => boolean;
}

const AuthScreen: React.FC<AuthScreenProps> = ({ onLogin, onRegister }) => {
  const [isLogin, setIsLogin] = useState(true);
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);
    await new Promise(resolve => setTimeout(resolve, 800));
    let success = false;
    if (isLogin) {
      success = onLogin(formData.email, formData.password);
      if (!success) setError('Credenciais inválidas.');
    } else {
      if (!formData.name || !formData.email || !formData.password) {
        setError('Preencha todos os campos.');
        setIsLoading(false);
        return;
      }
      success = onRegister(formData.name, formData.email, formData.password);
      if (!success) setError('E-mail indisponível.');
    }
    setIsLoading(false);
  };

  return (
    <div className="min-h-screen bg-black flex items-center justify-center p-6 relative overflow-hidden">
      <div className="absolute top-0 left-0 w-full h-full bg-[radial-gradient(ellipse_at_top,_var(--tw-gradient-stops))] from-gray-900 via-black to-black opacity-50" />

      <motion.div 
        initial={{ opacity: 0, y: 30 }}
        animate={{ opacity: 1, y: 0 }}
        className="w-full max-w-sm bg-black border border-agency-800 rounded-2xl p-8 relative z-10"
      >
        <div className="text-center mb-10">
          <h1 className="text-3xl font-bold text-white tracking-tighter mb-2">VANTAGE.</h1>
          <p className="text-agency-sub text-xs uppercase tracking-widest">Agency OS</p>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <AnimatePresence mode="popLayout">
            {!isLogin && (
              <motion.div initial={{ opacity: 0, height: 0 }} animate={{ opacity: 1, height: 'auto' }} exit={{ opacity: 0, height: 0 }}>
                <div className="relative group">
                  <User size={16} className="absolute left-4 top-4 text-agency-sub group-focus-within:text-white transition-colors" />
                  <input 
                    type="text"
                    placeholder="Nome"
                    className="w-full bg-agency-900 border border-agency-800 rounded py-3.5 pl-11 pr-4 outline-none focus:border-white transition-all text-sm text-white placeholder:text-agency-800"
                    value={formData.name}
                    onChange={e => setFormData({...formData, name: e.target.value})}
                  />
                </div>
              </motion.div>
            )}
          </AnimatePresence>

          <div className="relative group">
            <Mail size={16} className="absolute left-4 top-4 text-agency-sub group-focus-within:text-white transition-colors" />
            <input 
              type="email"
              placeholder="Email"
              className={`w-full bg-agency-900 border rounded py-3.5 pl-11 pr-4 outline-none focus:border-white transition-all text-sm text-white placeholder:text-agency-800 ${error ? 'border-red-900' : 'border-agency-800'}`}
              value={formData.email}
              onChange={e => setFormData({...formData, email: e.target.value})}
            />
          </div>

          <div className="relative group">
            <Lock size={16} className="absolute left-4 top-4 text-agency-sub group-focus-within:text-white transition-colors" />
            <input 
              type="password"
              placeholder="Senha"
              className={`w-full bg-agency-900 border rounded py-3.5 pl-11 pr-4 outline-none focus:border-white transition-all text-sm text-white placeholder:text-agency-800 ${error ? 'border-red-900' : 'border-agency-800'}`}
              value={formData.password}
              onChange={e => setFormData({...formData, password: e.target.value})}
            />
          </div>

          {error && <p className="text-red-500 text-xs text-center">{error}</p>}

          <button 
            type="submit"
            disabled={isLoading}
            className="w-full bg-white text-black py-4 rounded font-bold text-xs uppercase tracking-widest hover:bg-gray-200 transition-all flex items-center justify-center gap-2 mt-6"
          >
            {isLoading ? "Processando..." : (isLogin ? 'Entrar' : 'Registrar')}
          </button>
        </form>

        <div className="mt-8 text-center">
          <button 
            onClick={() => { setIsLogin(!isLogin); setError(''); }}
            className="text-agency-sub hover:text-white text-xs underline decoration-agency-800 hover:decoration-white underline-offset-4"
          >
            {isLogin ? 'Criar conta nova' : 'Já possuo conta'}
          </button>
        </div>
      </motion.div>
    </div>
  );
};

