                                <div className="flex-1">
                                    <p className={`font-medium text-sm ${task.completed ? 'text-white' : 'text-agency-text'}`}>{task.text}</p>
                                    <p className="text-[10px] text-agency-sub uppercase tracking-wider mt-1">{task.category} • {task.time}</p>
                                </div>
                            </div>
                        ))
                    )}
                </div>
             </motion.div>
           </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

