import React, { useState, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import MobileNav from './components/MobileNav';
import Header from './components/Header';
import DashboardHome from './components/DashboardHome';
import CRMView from './components/CRMView';
import TasksView from './components/TasksView';
import GoalsView from './components/GoalsView';
import ReportsView from './components/ReportsView';
import AuthScreen from './components/AuthScreen';
import { ViewState, Task, Lead, Goal, User, DatabaseSchema } from './types';
import { motion, AnimatePresence } from 'framer-motion';
import { CheckCircle2, XCircle } from 'lucide-react';

// --- Database Helper Functions ---
const DB_KEY = 'vantage_db_v1';

const getDB = (): DatabaseSchema => {
  const stored = localStorage.getItem(DB_KEY);
  return stored ? JSON.parse(stored) : { users: {} };
};

const saveDB = (db: DatabaseSchema) => {
  localStorage.setItem(DB_KEY, JSON.stringify(db));
};

// --- Default Tasks Logic ---
const generateDefaultTasks = (date: string): Task[] => [
  { id: `def-water-${Date.now()}`, text: "Ingerir 2L de água", completed: false, time: "08:00", category: "Lembrete", date },
  { id: `def-gym-${Date.now()}`, text: "Exercícios Físicos", completed: false, time: "18:00", category: "Academia", date },
  { id: `def-study-${Date.now()}`, text: "Estudo Diário", completed: false, time: "20:00", category: "Trabalho", date },
];

function App() {
  // --- Auth State ---
  const [user, setUser] = useState<User | null>(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isAuthChecking, setIsAuthChecking] = useState(true);

  // --- App State ---
  const [activeView, setActiveView] = useState<ViewState>('dashboard');
  const [tasks, setTasks] = useState<Task[]>([]);
  const [leads, setLeads] = useState<Lead[]>([]);
  const [goals, setGoals] = useState<Goal[]>([]);

  // --- PWA Install State ---
  const [installPrompt, setInstallPrompt] = useState<any>(null);

  // --- Toast Notification State ---
  const [toast, setToast] = useState<{ message: string; type: 'success' | 'error' } | null>(null);

  const showToast = (message: string, type: 'success' | 'error') => {
    setToast({ message, type });
    setTimeout(() => setToast(null), 3000);
  };

  useEffect(() => {
    // PWA Install Event Listener
    const handleBeforeInstallPrompt = (e: Event) => {
      e.preventDefault(); // Prevent automatic mini-infobar
      setInstallPrompt(e);
    };

    window.addEventListener('beforeinstallprompt', handleBeforeInstallPrompt);

    return () => {
      window.removeEventListener('beforeinstallprompt', handleBeforeInstallPrompt);
    };
  }, []);

  useEffect(() => {
    const db = getDB();
    if (db.lastUserEmail && db.users[db.lastUserEmail]) {
      const userData = db.users[db.lastUserEmail];
      setUser(userData.user);
      setIsAuthenticated(true);

      // Merge stored tasks with defaults if they don't exist for today
      let currentTasks = userData.data.tasks || [];
      const today = new Date().toISOString().split('T')[0];
      const hasDefaults = currentTasks.some(t => t.date === today && (t.text.includes("água") || t.text.includes("agua")));

      if (!hasDefaults) {
        const defaults = generateDefaultTasks(today);
        currentTasks = [...defaults, ...currentTasks];
      }

      setTasks(currentTasks);
      setLeads(userData.data.leads || []);
      setGoals(userData.data.goals || []);
    }
    setTimeout(() => setIsAuthChecking(false), 500);
  }, []);

  useEffect(() => {
    if (!isAuthenticated || !user) return;
    const db = getDB();
    if (db.users[user.email]) {
      db.users[user.email].data = { tasks, leads, goals };
      saveDB(db);
    }
  }, [tasks, leads, goals, isAuthenticated, user]);

  const handleLogin = (email: string, pass: string): boolean => {
    const db = getDB();
    const targetUser = db.users[email];
    if (targetUser && targetUser.password === pass) {
      setUser(targetUser.user);

      // Ensure defaults exist on login
      let currentTasks = targetUser.data.tasks || [];
      const today = new Date().toISOString().split('T')[0];
      const hasDefaults = currentTasks.some(t => t.date === today && (t.text.includes("água") || t.text.includes("agua")));

      if (!hasDefaults) {
         const defaults = generateDefaultTasks(today);
         currentTasks = [...defaults, ...currentTasks];
      }

      setTasks(currentTasks);
      setLeads(targetUser.data.leads);
      setGoals(targetUser.data.goals);
      db.lastUserEmail = email;
      saveDB(db);
      setIsAuthenticated(true);
      showToast(`Bem-vindo, ${targetUser.user.name.split(' ')[0]}`, 'success');
      return true;
    }
    return false;
  };

  const handleRegister = (name: string, email: string, pass: string): boolean => {
    const db = getDB();
    if (db.users[email]) return false;

    const today = new Date().toISOString().split('T')[0];
    const defaultTasks = generateDefaultTasks(today);

    const newUser: User = { name, email };
    db.users[email] = {
      password: pass,
      user: newUser,
      data: { tasks: defaultTasks, leads: [], goals: [] }
    };
    db.lastUserEmail = email;
    saveDB(db);
    setUser(newUser);
    setTasks(defaultTasks);
    setLeads([]);
    setGoals([]);
    setIsAuthenticated(true);
    showToast('Acesso concedido. Rotina iniciada.', 'success');
    return true;
  };

  const handleLogout = () => {
    const db = getDB();
    db.lastUserEmail = undefined;
    saveDB(db);
    setIsAuthenticated(false);
    setUser(null);
    setTasks([]);
    setLeads([]);
    setGoals([]);
    showToast('Sessão encerrada.', 'success');
  };

  const handleInstallApp = async () => {
    if (!installPrompt) return;
    installPrompt.prompt();
    const { outcome } = await installPrompt.userChoice;
    if (outcome === 'accepted') {
      setInstallPrompt(null);
      showToast('Aplicativo instalado com sucesso!', 'success');
    }
  };

  if (isAuthChecking) {
    return (
      <div className="h-screen w-screen bg-agency-black flex items-center justify-center">
         <div className="w-12 h-12 border-2 border-primary-500 border-t-transparent rounded-full animate-spin"></div>
      </div>
    );
  }

  if (!isAuthenticated) {
    return (
      <>
        <AuthScreen onLogin={handleLogin} onRegister={handleRegister} />
        <ToastContainer toast={toast} />
      </>
    );
  }

  return (
    <div className="flex h-screen bg-agency-black text-agency-text font-sans selection:bg-primary-500 selection:text-white overflow-hidden">
      <Sidebar 
        activeView={activeView} 
        setView={setActiveView} 
        onLogout={handleLogout} 
        onInstallApp={handleInstallApp}
        canInstall={!!installPrompt}
      />

      <div className="flex-1 flex flex-col relative h-full">
        <Header title={activeView} />

        <main className="flex-1 overflow-y-auto overflow-x-hidden p-4 md:p-8 scroll-smooth pb-28 lg:pb-8 pt-4">
          <div className="max-w-7xl mx-auto">
            <AnimatePresence mode="wait">
              <motion.div
                key={activeView}
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: -10 }}
                transition={{ duration: 0.3 }}
              >
                {activeView === 'dashboard' && <DashboardHome tasks={tasks} setTasks={setTasks} leads={leads} goals={goals} />}
                {activeView === 'crm' && <CRMView leads={leads} setLeads={setLeads} tasks={tasks} setTasks={setTasks} />}
                {activeView === 'tasks' && <TasksView tasks={tasks} setTasks={setTasks} />}
                {activeView === 'goals' && <GoalsView goals={goals} setGoals={setGoals} />}
                {activeView === 'reports' && <ReportsView tasks={tasks} leads={leads} />}
              </motion.div>
            </AnimatePresence>
          </div>
        </main>

        <MobileNav 
          activeView={activeView} 
          setView={setActiveView} 
          onInstallApp={handleInstallApp}
          canInstall={!!installPrompt}
        />
        <ToastContainer toast={toast} />
      </div>
    </div>
  );
}

const ToastContainer = ({ toast }: { toast: { message: string, type: 'success' | 'error' } | null }) => {
  return (
    <AnimatePresence>
      {toast && (
        <motion.div 
          initial={{ opacity: 0, y: -50, x: '-50%' }}
          animate={{ opacity: 1, y: 32, x: '-50%' }}
          exit={{ opacity: 0, y: -50, x: '-50%' }}
          className={`fixed top-0 left-1/2 z-[200] px-6 py-3 rounded-full shadow-2xl flex items-center gap-3 border backdrop-blur-md ${
            toast.type === 'success' 
              ? 'bg-success-500/10 text-success-500 border-success-500/50' 
              : 'bg-red-500/10 text-red-500 border-red-900'
          }`}
        >
          {toast.type === 'success' ? <CheckCircle2 size={18} /> : <XCircle size={18} />}
          <span className="font-bold text-sm tracking-wide">{toast.message}</span>
        </motion.div>
      )}
    </AnimatePresence>
  );
};

export default App;

{
  "name": "REMAKING",
  "description": "A premium life and business organization dashboard designed for high-performance individuals.",
  "requestFramePermissions": []
}

import React, { useState, useEffect, useRef } from 'react';
import { Check, Clock, Trash2, Zap } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Task } from '../types';

interface TasksViewProps {
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
}

const TasksView: React.FC<TasksViewProps> = ({ tasks, setTasks }) => {
  const [filter, setFilter] = useState<'all' | 'today' | 'pending'>('all');
  const [newTaskText, setNewTaskText] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<Task['category']>('Trabalho');
  const [showSuccess, setShowSuccess] = useState(false);

  const [permission, setPermission] = useState<NotificationPermission>('default');
  const notifiedTasks = useRef(new Set<string>());

  const today = new Date().toISOString().split('T')[0];

  useEffect(() => {
    if ('Notification' in window) setPermission(Notification.permission);
    const checkReminders = () => {
      if (!('Notification' in window) || Notification.permission !== 'granted') return;
      const now = new Date();
      tasks.forEach(task => {
        if (task.completed || notifiedTasks.current.has(task.id)) return;
        const taskDateTime = new Date(`${task.date}T${task.time}`);
        const diffMs = taskDateTime.getTime() - now.getTime();
        const diffMinutes = Math.floor(diffMs / 60000);
        if ((diffMinutes <= 10 && diffMinutes >= 0) || (diffMinutes < 0 && diffMinutes > -2)) {
          try {
            new Notification(`REMAKING: ${task.category}`, {
              body: diffMinutes <= 0 ? `HORA DE FAZER: ${task.text}` : `Faltam ${diffMinutes} min: "${task.text}"`,
              icon: 'https://i.imgur.com/kL00omR.png',
              tag: task.id,
              renotify: true,
              silent: false,
            } as any);
            if (navigator.vibrate) navigator.vibrate([200, 100, 200]);
            notifiedTasks.current.add(task.id);
          } catch (error) { console.error("Erro notificação:", error); }
        }
      });
    };
    checkReminders();
    const interval = setInterval(checkReminders, 60000);
    return () => clearInterval(interval);
  }, [tasks]);

  const requestNotificationPermission = async () => {
    if (!('Notification' in window)) return;
    const result = await Notification.requestPermission();
    setPermission(result);
  };

  const handleAddTask = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newTaskText.trim()) return;
    const newTask: Task = {
      id: Date.now().toString(),
      text: newTaskText,
      completed: false,
      date: today,
      time: new Date().toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' }),
      category: selectedCategory
    };
    setTasks([newTask, ...tasks]);
    setNewTaskText('');
    setShowSuccess(true);
    setTimeout(() => setShowSuccess(false), 1500);
  };

  const toggleTask = (id: string) => setTasks(tasks.map(t => t.id === id ? { ...t, completed: !t.completed } : t));
  const deleteTask = (id: string) => setTasks(tasks.filter(t => t.id !== id));

  const filteredTasks = tasks.filter(t => {
    if (filter === 'today') return t.date === today;
    if (filter === 'pending') return !t.completed;
    return true;
  });

  const getCategoryColor = (cat: string, active: boolean) => {
    if (!active) return 'bg-transparent text-agency-sub border-agency-800 hover:text-white';
    switch (cat) {
      case 'Trabalho': return 'bg-blue-500 text-white border-blue-500 shadow-glow';
      case 'Academia': return 'bg-orange-500 text-white border-orange-500 shadow-glow';
      case 'Lembrete': return 'bg-purple-500 text-white border-purple-500 shadow-glow';
      default: return 'bg-white text-black';
    }
  };

  const getCategoryTagStyle = (cat: string) => {
      switch(cat) {
          case 'Trabalho': return 'text-blue-400 border-blue-400/30 bg-blue-400/10';
          case 'Academia': return 'text-orange-400 border-orange-400/30 bg-orange-400/10';
          case 'Lembrete': return 'text-purple-400 border-purple-400/30 bg-purple-400/10';
          default: return 'text-gray-400 border-gray-400/30';
      }
  }

  return (
    <div className="max-w-4xl mx-auto pb-24">
      <div className="mb-8 flex flex-col md:flex-row md:items-end justify-between gap-4">
        <div>
          <h2 className="text-3xl font-bold text-white tracking-tighter mb-1">Agenda</h2>
          <p className="text-agency-sub text-sm">Organize sua produtividade.</p>
        </div>
        {permission !== 'granted' && 'Notification' in window && (
          <button onClick={requestNotificationPermission} className="text-xs font-bold bg-primary-600 text-white px-4 py-2 rounded uppercase tracking-wider hover:bg-primary-500 transition-colors shadow-glow">
            Ativar Notificações
          </button>
        )}
      </div>

      {/* Agency Input Area */}
      <form onSubmit={handleAddTask} className="relative mb-8">
        <div className="relative bg-agency-900 p-2 rounded-lg border border-agency-800 flex flex-col md:flex-row gap-2">
          <div className="flex-1 relative">
            <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
              <Zap size={18} className="text-primary-500" />
            </div>
            <input 
              type="text" 
              value={newTaskText}
              onChange={(e) => setNewTaskText(e.target.value)}
              placeholder="Digite uma nova tarefa..." 
              className="w-full h-12 md:h-14 pl-11 pr-4 bg-transparent outline-none text-white placeholder:text-agency-sub/50 font-medium text-base md:text-lg"
            />
          </div>

          <div className="flex items-center gap-2 px-2 pb-2 md:pb-0 justify-between md:justify-end border-t border-agency-800 md:border-t-0 pt-2 md:pt-0">
             <div className="flex gap-1">
              {(['Trabalho', 'Academia', 'Lembrete'] as Task['category'][]).map(cat => (
                <button
                  key={cat}
                  type="button"
                  onClick={() => setSelectedCategory(cat)}
                  className={`px-3 py-2 rounded text-[10px] font-bold uppercase tracking-wider transition-all border ${getCategoryColor(cat, selectedCategory === cat)}`}
                >
                  {cat}
                </button>
              ))}
            </div>

            <button 
              type="submit"
              disabled={showSuccess}
              className={`h-10 md:h-12 px-6 rounded flex items-center justify-center gap-2 transition-all duration-300 font-bold uppercase tracking-wide text-sm ${
                showSuccess ? 'bg-success-500 text-white' : 'bg-white text-black hover:bg-gray-200'
              }`}
            >
              <AnimatePresence mode="wait" initial={false}>
                {showSuccess ? <motion.div key="c"><Check size={20} /></motion.div> : <motion.div key="p">ADD</motion.div>}
              </AnimatePresence>
            </button>
          </div>
        </div>
      </form>

      {/* Filters */}
      <div className="flex gap-2 mb-6 border-b border-agency-800 pb-2">
        {['all', 'today', 'pending'].map((f) => (
          <button
            key={f}
            onClick={() => setFilter(f as any)}
            className={`px-4 py-2 text-xs font-bold uppercase tracking-widest transition-all ${
              filter === f 
                ? 'text-primary-500 border-b-2 border-primary-500' 
                : 'text-agency-sub hover:text-white'
            }`}
          >
            {f === 'all' ? 'Todas' : f === 'today' ? 'Hoje' : 'Pendentes'}
          </button>
        ))}
      </div>

      {/* Task List */}
      <div className="space-y-2">
        <AnimatePresence mode="popLayout">
          {filteredTasks.length === 0 ? (
            <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="text-center py-20 text-agency-sub">
               <p className="font-medium">Sem tarefas.</p>
            </motion.div>
          ) : (
            filteredTasks.map((task) => (
              <motion.div
                layout
                key={task.id}
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0 }}
                className={`group flex items-center p-4 bg-black rounded border transition-all duration-300 ${
                  task.completed ? 'border-agency-800 opacity-50' : 'border-agency-800 hover:border-primary-500/50'
                }`}
              >
                <button 
                  onClick={() => toggleTask(task.id)}
                  className={`flex-shrink-0 w-5 h-5 rounded border flex items-center justify-center mr-4 transition-all duration-300 ${
                    task.completed ? 'bg-success-500 border-success-500' : 'border-agency-sub hover:border-primary-500'
                  }`}
                >
                  {task.completed && <Check size={12} className="text-black" />}
                </button>

                <div className="flex-1">
                  <p className={`text-sm font-medium ${task.completed ? 'text-agency-sub line-through' : 'text-white'}`}>
                    {task.text}
                  </p>
                  <div className="flex items-center gap-3 mt-1 text-xs text-agency-sub">
                    <span className={`uppercase font-bold tracking-wider text-[10px] px-1.5 py-0.5 rounded border ${getCategoryTagStyle(task.category)}`}>{task.category}</span>
                    <span className="flex items-center gap-1 font-mono text-agency-sub"><Clock size={10} /> {task.time}</span>
                  </div>
                </div>

                <button onClick={() => deleteTask(task.id)} className="opacity-0 group-hover:opacity-100 p-2 text-agency-sub hover:text-red-500 transition-all">
                  <Trash2 size={16} />
                </button>
              </motion.div>
            ))
          )}
        </AnimatePresence>
      </div>
    </div>
  );
};

export default TasksView;

import React, { useState } from 'react';
import { Plus, Building2, Trash2, Wallet, Users, LayoutList, FileText, X, User, DollarSign } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Lead, Task } from '../types';

interface CRMViewProps {
  leads: Lead[];
  setLeads: React.Dispatch<React.SetStateAction<Lead[]>>;
  tasks: Task[];
  setTasks: React.Dispatch<React.SetStateAction<Task[]>>;
}

const CRMView: React.FC<CRMViewProps> = ({ leads, setLeads, tasks, setTasks }) => {
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newLead, setNewLead] = useState<Partial<Lead>>({ status: 'Potencial' });
  const [activeMobileTab, setActiveMobileTab] = useState<Lead['status']>('Ativo');

  const [editingNoteLead, setEditingNoteLead] = useState<Lead | null>(null);
  const [noteText, setNoteText] = useState('');

  const columns: { id: Lead['status']; label: string; color: string; borderColor: string; }[] = [
    { id: 'Potencial', label: 'Interesse', color: 'text-blue-400', borderColor: 'border-blue-500/30' },
    { id: 'Negociacao', label: 'Negociando', color: 'text-warning-500', borderColor: 'border-warning-500/30' },
    { id: 'Ativo', label: 'Ativos', color: 'text-success-500', borderColor: 'border-success-500/30' },
    { id: 'Arquivado', label: 'Arquivados', color: 'text-gray-500', borderColor: 'border-gray-500/30' },
  ];

  const monthlyRevenue = leads
    .filter(l => l.status === 'Ativo')
    .reduce((acc, curr) => acc + curr.value, 0);

  const activeClientsCount = leads.filter(l => l.status === 'Ativo').length;

  const handleAddLead = () => {
    if (!newLead.name || !newLead.value || newLead.value <= 0) return;
    const lead: Lead = {
      id: Date.now().toString(),
      name: newLead.name,
      company: newLead.company || 'Pessoal',
      value: Number(newLead.value),
      status: 'Potencial',
      lastContact: new Date().toLocaleDateString('pt-BR'),
      phone: newLead.phone || '',
      notes: ''
    };
    const newTask: Task = {
      id: `auto-task-${Date.now()}`,
      text: `Otimizar: ${newLead.name}`,
      completed: false,
      date: new Date().toISOString().split('T')[0], 
      time: '09:00', 
      category: 'Trabalho'
    };
    setLeads([...leads, lead]);
    setTasks(prevTasks => [newTask, ...prevTasks]);
    setIsModalOpen(false);
    setNewLead({ status: 'Potencial' });

    // Trigger Notification
    if ('Notification' in window && Notification.permission === 'granted') {
      try {
        new Notification("REMAKING", {
          body: `Novo cliente cadastrado com sucesso: ${lead.name}`,
          icon: 'https://i.imgur.com/kL00omR.png'
        });
      } catch (e) { console.log("Notificação falhou", e); }
    }
  };

  const deleteLead = (id: string) => setLeads(leads.filter(l => l.id !== id));
  const moveLead = (id: string, newStatus: Lead['status']) => setLeads(leads.map(l => l.id === id ? { ...l, status: newStatus } : l));

  const openNoteModal = (lead: Lead) => {
    setEditingNoteLead(lead);
    setNoteText(lead.notes || '');
  };

  const saveNote = () => {
    if (editingNoteLead) {
      setLeads(leads.map(l => l.id === editingNoteLead.id ? { ...l, notes: noteText } : l));
      setEditingNoteLead(null);
      setNoteText('');
    }
  };

  return (
    <div className="h-full flex flex-col pb-safe w-full max-w-full overflow-x-hidden">

      {/* SECTION 1: HEADER (STATS) */}
      <div className="w-full bg-agency-900 border border-agency-800 text-white rounded-xl p-6 mb-6 flex flex-col gap-4 relative overflow-hidden shrink-0">
         {/* Glow effect */}
         <div className="absolute top-0 right-0 w-64 h-64 bg-primary-500/10 rounded-full blur-3xl pointer-events-none"></div>

        <div className="relative z-10 w-full flex flex-col gap-3 md:grid md:grid-cols-2 md:gap-4">
          <div className="w-full bg-black/40 border border-agency-800 rounded-lg p-4 flex items-center gap-3">
             <div className="p-2 bg-success-500/20 text-success-500 rounded shrink-0"><Wallet size={18} /></div>
             <div className="flex-1 min-w-0">
               <p className="text-agency-sub text-[10px] uppercase tracking-wide font-bold truncate">MRR</p>
               <h2 className="text-xl font-bold tracking-tight truncate text-white">
                 R$ {monthlyRevenue.toLocaleString('pt-BR', { notation: "compact", maximumFractionDigits: 1 })}
               </h2>
             </div>
          </div>

          <div className="w-full bg-black/40 border border-agency-800 rounded-lg p-4 flex items-center gap-3">
              <div className="p-2 bg-blue-500/20 text-blue-500 rounded shrink-0"><Users size={18} /></div>
              <div className="flex-1 min-w-0">
                <p className="text-agency-sub text-[10px] uppercase font-bold truncate">Clientes Ativos</p>
                <h2 className="text-xl font-bold truncate text-white">{activeClientsCount}</h2>
              </div>
           </div>
        </div>

        <button 
          onClick={() => setIsModalOpen(true)}
          className="w-full bg-gradient-to-r from-primary-600 to-indigo-600 text-white py-4 rounded-lg flex items-center justify-center gap-2 hover:shadow-glow transition-all font-bold active:scale-95 relative z-10 text-sm tracking-wide uppercase"
        >
          <Plus size={16} /> Novo Cliente
        </button>
      </div>

      {/* SECTION 2: FILTERS (TABS) */}
      <div className="md:hidden w-full mb-6">
        <div className="flex flex-wrap gap-2 w-full">
          {columns.map(col => (
            <button
              key={col.id}
              onClick={() => setActiveMobileTab(col.id)}
              className={`flex-1 min-w-[45%] px-3 py-2.5 rounded text-xs font-bold transition-all border text-center uppercase tracking-wider ${
                activeMobileTab === col.id 
                  ? `bg-agency-900 border-primary-500 text-white shadow-lg` 
                  : 'bg-transparent text-agency-sub border-agency-800'
              }`}
            >
              {col.label} <span className="opacity-50 ml-1">({leads.filter(l => l.status === col.id).length})</span>
            </button>
          ))}
        </div>
      </div>

      {/* SECTION 3: CONTENT AREA */}
      <div className="flex-1 min-h-0 w-full">
        {/* Desktop View */}
        <div className="hidden md:flex gap-4 h-full pb-4 overflow-x-auto">
          {columns.map(col => (
             <Column 
               key={col.id} 
               col={col} 
               leads={leads} 
               moveLead={moveLead} 
               deleteLead={deleteLead} 
               openNoteModal={openNoteModal}
             />
          ))}
        </div>

        {/* Mobile View */}
        <div className="md:hidden h-full w-full">
           <AnimatePresence mode="wait">
             <motion.div
               key={activeMobileTab}
               initial={{ opacity: 0, y: 10 }}
               animate={{ opacity: 1, y: 0 }}
               exit={{ opacity: 0, y: -10 }}
               className="space-y-3 pb-20 w-full"
             >
               {leads.filter(l => l.status === activeMobileTab).length === 0 ? (
                 <div className="text-center py-12 text-agency-sub flex flex-col items-center">
                    <LayoutList size={32} className="mb-2 opacity-20" />
                    <p className="text-sm">Vazio.</p>
                 </div>
               ) : (
                 leads.filter(l => l.status === activeMobileTab).map(lead => (
                   <LeadCard 
                     key={lead.id} 
                     lead={lead} 
                     moveLead={moveLead} 
                     deleteLead={deleteLead} 
                     openNoteModal={openNoteModal}
                   />
                 ))
               )}
             </motion.div>
           </AnimatePresence>
        </div>
      </div>

      {/* Add Lead Modal */}
      <AnimatePresence>
        {isModalOpen && (
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-[100] bg-black/80 backdrop-blur-sm flex items-center justify-center p-4"
          >
            <motion.div 
              initial={{ scale: 0.9, y: 20 }} animate={{ scale: 1, y: 0 }}
              className="bg-agency-900 border border-agency-800 rounded-xl w-[95%] max-w-md p-6 shadow-2xl relative"
            >
              <div className="flex justify-between items-center mb-6 border-b border-agency-800 pb-4">
                 <h3 className="text-lg font-bold text-white uppercase tracking-wide">Novo Cliente</h3>
                 <button onClick={() => setIsModalOpen(false)} className="text-agency-sub hover:text-white"><X size={20} /></button>
              </div>

              <div className="space-y-4">
                <InputGroup icon={User} label="Nome" value={newLead.name} onChange={v => setNewLead({...newLead, name: v})} placeholder="Ex: Roberto Almeida" />
                <InputGroup icon={Building2} label="Empresa/Serviço" value={newLead.company} onChange={v => setNewLead({...newLead, company: v})} placeholder="Ex: Consultoria" />
                <InputGroup 
                  icon={DollarSign} 
                  label="Valor Mensal" 
                  value={newLead.value} 
                  onChange={v => {
                    const val = parseFloat(v);
                    if (v === '') {
                        setNewLead({...newLead, value: undefined});
                    } else if (!isNaN(val) && val >= 0) {
                        setNewLead({...newLead, value: val});
                    }
                  }} 
                  placeholder="0.00" 
                  type="number" 
                />
              </div>

              <div className="flex justify-end gap-3 mt-8 pt-4 border-t border-agency-800">
                <button onClick={() => setIsModalOpen(false)} className="px-5 py-3 text-agency-sub hover:text-white text-sm transition-colors">Cancelar</button>
                <button onClick={handleAddLead} className="px-8 py-3 bg-gradient-to-r from-primary-600 to-primary-500 text-white rounded font-bold hover:shadow-glow text-sm uppercase tracking-wide">Salvar</button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>

      {/* Notes Modal */}
      <AnimatePresence>
        {editingNoteLead && (
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-[110] bg-black/80 backdrop-blur-sm flex items-center justify-center p-4"
          >
            <motion.div 
              initial={{ scale: 0.95, y: 20 }} animate={{ scale: 1, y: 0 }}
              className="bg-agency-900 border border-agency-800 rounded-xl w-full max-w-2xl p-6 md:p-8 shadow-2xl flex flex-col h-[85vh] md:h-[650px]"
            >
              <div className="flex justify-between items-center mb-6 flex-shrink-0">
                <div>
                   <h3 className="text-xl font-bold text-white">Notas: {editingNoteLead.name}</h3>
                </div>
                <button onClick={() => setEditingNoteLead(null)} className="text-agency-sub hover:text-white"><X size={24} /></button>
              </div>

              <textarea 
                className="flex-1 w-full p-6 bg-black border border-agency-800 rounded-lg focus:border-primary-500 focus:ring-1 focus:ring-primary-500 outline-none transition-all resize-none text-white text-base leading-relaxed font-mono"
                placeholder="Detalhes do projeto..."
                value={noteText}
                onChange={e => setNoteText(e.target.value)}
                autoFocus
              />

              <div className="flex justify-end mt-4 pt-4 border-t border-agency-800">
                  <button onClick={saveNote} className="px-8 py-3 bg-white text-black rounded font-bold hover:bg-gray-200 text-sm uppercase tracking-wide flex items-center gap-2">
                    <FileText size={16} /> Salvar
                  </button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
};

// Components
const InputGroup = ({ icon: Icon, label, value, onChange, placeholder, type = "text" }: any) => (
  <div className="space-y-1.5">
     <label className="text-[10px] font-bold text-agency-sub uppercase tracking-widest ml-1">{label}</label>
     <div className="relative group">
        <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none text-agency-sub group-focus-within:text-white transition-colors">
          <Icon size={16} />
        </div>
        <input 
          type={type}
          className="w-full pl-10 pr-4 py-3 bg-black border border-agency-800 rounded outline-none focus:border-primary-500 focus:ring-1 focus:ring-primary-500 transition-all text-sm font-medium text-white placeholder:text-agency-800"
          placeholder={placeholder}
          value={value || ''}
          onChange={e => onChange(e.target.value)}
        />
     </div>
  </div>
);

const Column = ({ col, leads, moveLead, deleteLead, openNoteModal }: any) => (
  <div className={`min-w-[85vw] md:min-w-[320px] flex-1 flex flex-col rounded-xl p-4 border border-agency-800 bg-agency-900/50`}>
    <div className={`flex items-center gap-2 mb-4 px-1 border-b pb-2 ${col.borderColor}`}>
      <span className={`font-bold text-sm uppercase tracking-wider ${col.color}`}>{col.label}</span>
      <span className="ml-auto text-xs font-bold text-white bg-agency-800 px-2 py-0.5 rounded">
        {leads.filter((l: Lead) => l.status === col.id).length}
      </span>
    </div>
    <div className="flex-1 space-y-3 overflow-y-auto scrollbar-thin pr-1">
      {leads.filter((l: Lead) => l.status === col.id).map((lead: Lead) => (
        <LeadCard key={lead.id} lead={lead} moveLead={moveLead} deleteLead={deleteLead} openNoteModal={openNoteModal} />
      ))}
    </div>
  </div>
);

const LeadCard = ({ lead, moveLead, deleteLead, openNoteModal }: any) => (
  <motion.div 
    layoutId={lead.id}
    className="bg-black p-4 rounded border border-agency-800 hover:border-primary-500 transition-colors group relative w-full shadow-lg"
  >
    <div className="flex justify-between items-start mb-2 gap-2">
      <span className="font-bold text-white text-base truncate flex-1 min-w-0">{lead.name}</span>
      <div className="flex gap-2 flex-shrink-0">
        <button onClick={(e) => { e.stopPropagation(); openNoteModal(lead); }} className="text-agency-sub hover:text-white"><FileText size={14} /></button>
        <button onClick={() => deleteLead(lead.id)} className="text-agency-sub hover:text-red-500"><Trash2 size={14} /></button>
      </div>
    </div>
    <div className="text-xs text-agency-sub mb-4 flex items-center gap-1">
      <Building2 size={10} /> {lead.company}
    </div>

    <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center pt-3 border-t border-agency-800 gap-3">
      <span className="font-mono font-bold text-success-500 text-sm">
        {lead.value.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 })}
      </span>

      <div className="flex gap-2 flex-wrap justify-end sm:justify-end">
         {lead.status !== 'Ativo' && <ActionButton onClick={() => moveLead(lead.id, 'Ativo')} text="Fechar" primary />}
         {lead.status === 'Ativo' && <ActionButton onClick={() => moveLead(lead.id, 'Arquivado')} text="Arquivar" />}
         {lead.status === 'Potencial' && <ActionButton onClick={() => moveLead(lead.id, 'Negociacao')} text="Negociar" />}
         {lead.status === 'Negociacao' && <ActionButton onClick={() => moveLead(lead.id, 'Potencial')} text="Voltar" />}
      </div>
    </div>
  </motion.div>
);

const ActionButton = ({ onClick, text, primary }: any) => (
  <button 
    onClick={onClick}
    className={`text-[10px] px-3 py-1.5 rounded font-bold uppercase tracking-wide transition-colors ${
      primary ? 'bg-primary-600 text-white hover:bg-primary-500 hover:shadow-glow' : 'bg-agency-800 text-agency-sub hover:text-white hover:bg-agency-700'
    }`}
  >
    {text}
  </button>
);

