}

export interface StatCardProps {
  label: string;
  value: string;
  trend?: string;
  isPositive?: boolean;
  icon: LucideIcon;
}

export interface FeatureCardProps {
  id: string;
  title: string;
  subtitle: string;
  icon: LucideIcon;
  ctaText: string;
  gradient: string;
